    // ========== iLens 전송: Queue 방식 (Flutter와 동일) ==========
    // 1초마다 모든 메트릭을 queue에 추가 → 순차 전송
    // iLens는 WRITE_WITH_RESPONSE만 지원 → onCharacteristicWrite() callback에서 다음 패킷 전송
    if (_isConnected && _exerciseCharacteristic != null) {
        try {
