package com.runvision.wear.ble

import android.annotation.SuppressLint
import android.bluetooth.BluetoothAdapter
import android.bluetooth.BluetoothDevice
import android.bluetooth.le.ScanCallback
import android.bluetooth.le.ScanResult
import android.bluetooth.le.ScanSettings
import android.content.Context
import android.util.Log

/**
 * BLE Scanner for rLens devices
 *
 * Filters devices by name containing "rlens" (case-insensitive)
 * Also checks raw scan record bytes for device name (some devices advertise there)
 *
 * Reference: runvision-iq/source/RunVisionIQView.mc:778-801
 */
@SuppressLint("MissingPermission")
class RLensScanner(
    private val context: Context,
    private val onDeviceFound: (BluetoothDevice) -> Unit
) {
    companion object {
        private const val TAG = "RLensScanner"
    }

    private val bluetoothAdapter: BluetoothAdapter? = BluetoothAdapter.getDefaultAdapter()
    private var isScanning = false
    private var deviceFound = false  // Prevent multiple connections

    private val scanCallback = object : ScanCallback() {
        override fun onScanResult(callbackType: Int, result: ScanResult) {
            if (deviceFound) return  // Already found, ignore subsequent results

            val device = result.device
            val deviceName = device.name?.lowercase() ?: ""

            // Also check raw scan record for device name
            val scanRecord = result.scanRecord?.bytes?.let { bytes ->
                String(bytes.filter { it in 0x20..0x7E }.toByteArray())
            }?.lowercase() ?: ""

            // Filter: "rlens" only (case-insensitive)
            if (deviceName.contains("rlens") ||
                scanRecord.contains("rlens")) {
                deviceFound = true
                Log.d(TAG, "Found rLens device: ${device.name} (${device.address})")
                stopScan()
                onDeviceFound(device)
            }
        }

        override fun onScanFailed(errorCode: Int) {
            Log.e(TAG, "Scan failed with error: $errorCode")
            isScanning = false
        }
    }

    /**
     * Start scanning for rLens devices
     */
    fun startScan() {
        if (isScanning) return
        if (bluetoothAdapter == null || !bluetoothAdapter.isEnabled) {
            Log.e(TAG, "Bluetooth not available or disabled")
            return
        }

        val scanner = bluetoothAdapter.bluetoothLeScanner ?: return
        val settings = ScanSettings.Builder()
            .setScanMode(ScanSettings.SCAN_MODE_LOW_LATENCY)
            .build()

        Log.d(TAG, "Starting BLE scan...")
        deviceFound = false  // Reset for new scan
        isScanning = true
        scanner.startScan(null, settings, scanCallback)
    }

    /**
     * Stop scanning
     */
    fun stopScan() {
        if (!isScanning) return
        bluetoothAdapter?.bluetoothLeScanner?.stopScan(scanCallback)
        isScanning = false
        Log.d(TAG, "Stopped BLE scan")
    }

    fun isScanning(): Boolean = isScanning
}

        onDistanceUpdate = { meters ->
            Log.d(TAG, "Distance update: $meters m")
            runningEngine.updateDistance(meters)
        }
        onStepsDeltaUpdate = { steps ->
            Log.d(TAG, "Step delta: $steps")
            runningEngine.updateStepsDelta(steps)
        }
    }

    createNotificationChannel()

    // BLE 초기화 - Service context로 생성하여 Activity lifecycle과 분리
    initializeBle()

    // Start immediate heart rate measurement (before exercise starts)
    serviceScope.launch {
        exerciseManager.startMeasuringHeartRate()
    }
}

/**
 * BLE 컴포넌트 초기화
 * Service context로 생성하여 화면 꺼져도 BLE 연결 유지
 */
@android.annotation.SuppressLint("MissingPermission")
private fun initializeBle() {
    Log.d(TAG, "Initializing BLE components with Service context")

    rLensScanner = RLensScanner(this) { device ->
        Log.d(TAG, "Found rLens device: ${device.name}")
        scanTimeoutJob?.cancel()  // Cancel timeout - device found
        rLensConnection?.connect(device)
    }

    rLensConnection = RLensConnection(this) { state ->
        Log.d(TAG, "BLE connection state: $state")
        _connectionState.value = state

        // 연결 완료 시 자동으로 운동 시작
        if (state == RLensConnection.ConnectionState.CONNECTED && !_isRunning.value) {
            Log.d(TAG, "Auto-starting exercise on BLE connection")
            startExercise()
        }
    }
}

// Scan timeout job
private var scanTimeoutJob: Job? = null
private val SCAN_TIMEOUT_MS = 10000L  // 10 seconds

/**
 * BLE 스캔 시작
 * 10초 타임아웃 후 NOT_FOUND 상태로 전환
 */
fun startScanning() {
    Log.d(TAG, "Starting BLE scan")
    _connectionState.value = RLensConnection.ConnectionState.SCANNING
    rLensScanner?.startScan()

    // Start timeout
    scanTimeoutJob?.cancel()
    scanTimeoutJob = serviceScope.launch {
        delay(SCAN_TIMEOUT_MS)
        if (_connectionState.value == RLensConnection.ConnectionState.SCANNING) {
            Log.w(TAG, "Scan timeout - device not found")
            rLensScanner?.stopScan()
            _connectionState.value = RLensConnection.ConnectionState.NOT_FOUND
        }
    }
}

/**
 * BLE 스캔 중지
 */
fun stopScanning() {
    Log.d(TAG, "Stopping BLE scan")
    scanTimeoutJob?.cancel()
    rLensScanner?.stopScan()
}

override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
    Log.d(TAG, "onStartCommand")
    // Acquire wake lock immediately when service starts foreground
    acquireWakeLock()
    if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.UPSIDE_DOWN_CAKE) {
        startForeground(NOTIFICATION_ID, createNotification(), ServiceInfo.FOREGROUND_SERVICE_TYPE_HEALTH)
    } else {
        startForeground(NOTIFICATION_ID, createNotification())
    }
    return START_STICKY
}

override fun onDestroy() {
    super.onDestroy()
    Log.d(TAG, "ExerciseService destroyed")
    serviceScope.cancel()
    timerJob?.cancel()

