115	  // CRITICAL: Official iLens app writes 3 initialization commands after connection:
116	  //   - [0x10, 0x01]: Read resource package version and language
117	  //   - [0x10, 0x04]: Read traditional Bluetooth address
118	  //   - [0x10, 0x03]: Read translation display setting
119	  // These MUST be sent before any settings writes, otherwise GATT_ERROR occurs!
120	  static const String universalSubCharUuid = 'c1329ce5-b463-31a5-8b78-bd220c1480cd';
121	
122	  static const Duration scanTimeout = Duration(seconds: 5);
123	  static const int mtuSize = 244;
124	
125	  // ============================================================
126	  // PUBLIC METHODS
127	  // ============================================================
128	
129	  /// iLens 기기 스캔
130	  ///
131	  /// [timeout] 스캔 타임아웃
132	  /// Returns: List<BluetoothDevice>
133	  Future<List<BluetoothDevice>> scanForDevices({
134	    Duration? timeout,
135	  }) async {
136	    try {
137	      developer.log('[ILENS] Starting scan for iLens devices', name: 'runvision');
138	
139	      final devices = <BluetoothDevice>[];
140	      final scanCompleter = Completer<List<BluetoothDevice>>();
141	
142	      // Start scanning
143	      final subscription = FlutterBluePlus.scanResults.listen((results) {
144	        print('=== [ILENS SCAN] Received ${results.length} scan results');
145	        for (final result in results) {
146	          final device = result.device;
147	          final deviceName = device.platformName.toLowerCase();
148	
149	          print('=== [ILENS SCAN] Device: ${device.platformName} (${device.remoteId.str})');
150	
151	          // iLens 기기는 advertisement data에 서비스 UUID를 포함하지 않으므로
152	          // 모든 기기를 표시하되, 이름에 "ilens"가 포함된 기기를 우선 표시
153	          // 실제 서비스 확인은 연결 후 service discovery에서 수행
154	
155	          // Add unique devices only
156	          if (!devices.any((d) => d.remoteId.str == device.remoteId.str)) {
157	            devices.add(device);
158	            print('=== [ILENS SCAN] ✓ Added device: ${device.platformName} (${device.remoteId.str})');
159	
160	            if (deviceName.contains('rlens')) {
161	              print('=== [ILENS SCAN] 🎯 Potential rLens device found by name');
162	              developer.log('[ILENS] Potential rLens device found: ${device.platformName} (${device.remoteId.str})', name: 'runvision');
163	            }
164	          }
165	        }
166	      });
167	
168	      // Start scan
169	      await FlutterBluePlus.startScan(
170	        timeout: timeout ?? scanTimeout,
171	        // withServices: [Guid(ilensServiceUuid)],
172	      );
173	
174	      // Wait for scan to complete
175	      await Future.delayed(timeout ?? scanTimeout);
176	      await FlutterBluePlus.stopScan();
177	      await subscription.cancel();
178	
179	      // Sort devices: iLens/rLens devices first, then others
180	      devices.sort((a, b) {
181	        final aName = a.platformName.toLowerCase();
182	        final bName = b.platformName.toLowerCase();
183	        final aHasIlens = aName.contains('rlens');
184	        final bHasIlens = bName.contains('rlens');
185	        if (aHasIlens && !bHasIlens) return -1;
186	        if (!aHasIlens && bHasIlens) return 1;
187	        return a.platformName.compareTo(b.platformName);
188	      });
189	
190	      developer.log('[ILENS] Scan completed. Found ${devices.length} devices', name: 'runvision');
191	      return devices;
192	    } catch (e, stackTrace) {
193	      developer.log('[ILENS] Scan failed: $e', name: 'runvision', stackTrace: stackTrace);
194	      throw Failure.unexpected(
