201	  /// iLens 연결
202	  ///
203	  /// [deviceId] Bluetooth Device ID
204	  /// Returns: Future<void>
205	  /// Throws: Failure
206	  Future<void> connect(String deviceId) async {
207	    print('=== [ILENS CONNECT] Connecting to device: $deviceId');
208	    developer.log('[ILENS] Connecting to device: $deviceId', name: 'runvision');
209	    try {
210	      // First check if device is already connected
211	      final connectedDevices = FlutterBluePlus.connectedDevices;
212	      BluetoothDevice? device;
213	
214	      // Try to find in already connected devices
215	      try {
216	        device = connectedDevices.firstWhere(
217	          (d) => d.remoteId.str == deviceId,
218	        );
219	        print('=== [ILENS CONNECT] Device already connected');
220	        developer.log('[ILENS] Device already connected', name: 'runvision');
221	      } catch (e) {
222	        // Not connected yet, create device from remoteId
223	        print('=== [ILENS CONNECT] Device not connected, creating BluetoothDevice from ID');
224	        developer.log('[ILENS] Device not connected, creating BluetoothDevice from ID', name: 'runvision');
225	        device = BluetoothDevice.fromId(deviceId);
226	        print('=== [ILENS CONNECT] Created device: ${device.platformName}');
227	        developer.log('[ILENS] Created device: ${device.platformName}', name: 'runvision');
228	
229	        // Connect to device
230	        print('=== [ILENS CONNECT] Calling device.connect()...');
231	        developer.log('[ILENS] Connecting to device...', name: 'runvision');
232	        await device.connect(
233	          license: License.free,  // Free for individuals & small organizations (<50 employees)
234	          timeout: const Duration(seconds: 10),
235	        );
236	        print('=== [ILENS CONNECT] device.connect() completed');
237	        developer.log('[ILENS] Device.connect() completed', name: 'runvision');
238	      }
239	
240	      _connectedDevice = device;
241	      _lastDeviceId = deviceId;
242	      _autoReconnectEnabled = true;
243	      _reconnectAttempts = 0;
244	
245	      // Monitor connection state with auto-reconnect
246	      _deviceStateSubscription?.cancel();
247	      _deviceStateSubscription = device.connectionState.listen((state) {
248	        print('=== [ILENS CONNECT] Connection state changed: $state');
249	        developer.log('[ILENS] Connection state: $state', name: 'runvision');
250	
251	        if (state == BluetoothConnectionState.disconnected) {
252	          print('=== [ILENS CONNECT] Device disconnected, attempting auto-reconnect');
253	          _stopKeepAlive();
254	          onDisconnected?.call();
255	          _handleDisconnection();
256	        } else if (state == BluetoothConnectionState.connected) {
257	          print('=== [ILENS CONNECT] Device connected');
258	          _reconnectAttempts = 0;
259	        }
260	      });
261	
262	      // MTU 협상
263	      print('=== [ILENS CONNECT] Requesting MTU: $mtuSize');
264	      developer.log('[ILENS] Requesting MTU: $mtuSize', name: 'runvision');
265	      await _connectedDevice!.requestMtu(mtuSize);
266	
267	      // Service Discovery
268	      print('=== [ILENS CONNECT] Starting service discovery');
269	      developer.log('[ILENS] Starting service discovery', name: 'runvision');
270	      await _discoverServices();
271	
272	      // Battery 구독 (1초 폴링)
273	      await _subscribeToBattery();
274	
275	      // CRITICAL: Send Universal Subscriptions initialization commands FIRST
276	      // This MUST happen before any other writes (time sync, config, settings)
277	      // iLens BLE V1.0.10.pdf Section 3.7: Universal Subscriptions
278	      // Official iLens app sends these 3 commands immediately after connection
279	      // This "warms up" the device and enables settings writes
280	      // CRITICAL: Must wait for NOTIFY responses, not just blindly wait 1200ms!
281	      if (_universalSubChar != null) {
282	        try {
283	          print('=== [ILENS INIT] Sending Universal Subscriptions initialization...');
284	
285	          // Enable notifications and subscribe to receive responses (official app does this)
286	          if (_universalSubChar!.properties.notify) {
287	            try {
288	              // Subscribe to notification stream
289	              final notifyStream = _universalSubChar!.onValueReceived;
290	              int responsesReceived = 0;
291	
292	              // Listen for responses (official app gets 3 NOTIFY responses)
293	              final responseCompleter = Completer<void>();
294	              final subscription = notifyStream.listen((value) {
295	                responsesReceived++;
296	                print('=== [ILENS INIT] ✓ Received NOTIFY response $responsesReceived: ${value.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');
297	
298	                // Parse firmware version from first response ([0x10, 0x01] response)
299	                // Format: [0x10, 0x01, length, version_bytes..., ...]
300	                if (responsesReceived == 1 && value.length >= 3 && value[0] == 0x10 && value[1] == 0x01) {
301	                  final versionLength = value[2];
302	                  if (value.length >= 3 + versionLength) {
303	                    final versionBytes = value.sublist(3, 3 + versionLength);
304	                    _firmwareVersion = String.fromCharCodes(versionBytes);
305	                    print('=== [ILENS INIT] ✓ Firmware version: $_firmwareVersion');
306	                  }
307	                }
308	
309	                if (responsesReceived >= 3) {
310	                  print('=== [ILENS INIT] ✓ All 3 initialization responses received');
311	                  if (!responseCompleter.isCompleted) {
312	                    responseCompleter.complete();
313	                  }
314	                }
315	              });
316	
317	              // Enable notifications FIRST
318	              await _universalSubChar!.setNotifyValue(true);
319	              print('=== [ILENS INIT] ✓ Enabled notify for Universal Subscriptions');
320	
321	              // Send initialization commands
322	              await _universalSubChar!.write([0x10, 0x01]);
323	              print('=== [ILENS INIT] ✓ Sent [0x10, 0x01] - Read version/language');
324	
325	              await _universalSubChar!.write([0x10, 0x04]);
326	              print('=== [ILENS INIT] ✓ Sent [0x10, 0x04] - Read BT address');
327	
328	              await _universalSubChar!.write([0x10, 0x03]);
329	              print('=== [ILENS INIT] ✓ Sent [0x10, 0x03] - Read translation setting');
330	
331	              // Wait for all 3 NOTIFY responses (with timeout)
332	              print('=== [ILENS INIT] Waiting for device NOTIFY responses...');
333	              await responseCompleter.future.timeout(
334	                const Duration(seconds: 2),
335	                onTimeout: () {
336	                  print('=== [ILENS INIT] ⚠️ Timeout waiting for NOTIFY responses (got $responsesReceived/3)');
337	                },
338	              );
339	
340	              // Cancel subscription after we're done
341	              await subscription.cancel();
342	
343	              // CRITICAL: Disable notify after initialization to prevent interference
344	              // Some BLE stacks have issues with multiple notify-enabled characteristics
345	              try {
346	                await _universalSubChar!.setNotifyValue(false);
347	                print('=== [ILENS INIT] ✓ Disabled notify for Universal Subscriptions');
348	              } catch (e) {
349	                print('=== [ILENS INIT] ⚠️ Failed to disable notify: $e');
350	              }
351	
352	              print('=== [ILENS INIT] ✓ Initialization complete, device ready for other writes');
353	
354	              // Re-emit status with firmware version (initial battery read missed it)
355	              if (_firmwareVersion != null) {
356	                _statusController.add(ILensStatus(
357	                  isConnected: true,
358	                  batteryLevel: _lastBatteryLevel,
359	                  timestamp: DateTime.now(),
360	                  firmwareVersion: _firmwareVersion,
361	                ));
362	              }
363	            } catch (e) {
364	              print('=== [ILENS INIT] ⚠️ Failed to complete initialization: $e');
365	            }
366	          }
367	        } catch (e) {
368	          print('=== [ILENS INIT] ⚠️ Initialization failed (non-critical): $e');
369	          // Continue anyway - device might still work
370	        }
371	      } else {
372	        print('=== [ILENS INIT] ⚠️ Universal Subscriptions characteristic not found - skipping initialization');
373	        print('=== [ILENS INIT] ⚠️ Settings writes may fail with GATT_ERROR!');
374	      }
375	
376	      // Time synchronization AFTER Universal Subscriptions init
377	      // Official iLens app sends time sync much later, but we need it for running metrics
378	      try {
379	        print('=== [ILENS CONNECT] Starting time synchronization...');
380	
381	        // Wait for iLens boot sequence to complete
382	        print('=== [ILENS CONNECT] Waiting 1000ms for iLens boot sequence...');
383	        await Future.delayed(const Duration(milliseconds: 1000));
384	
385	        // Send RTC sync (reason 0x03)
386	        final now = DateTime.now();
387	        print('=== [ILENS CONNECT] Sending RTC sync (reason 0x03) with time: ${now.toString()}');
388	        await _sendCurrentTimeWithTimestamp(now, reason: 0x03);
389	
390	        print('=== [ILENS CONNECT] ✓ Time synchronization completed');
391	        developer.log('[ILENS] Time synchronization completed', name: 'runvision');
392	      } catch (e) {
393	        print('=== [ILENS CONNECT] ⚠️ Time synchronization failed (non-critical): $e');
394	        developer.log('[ILENS] Time synchronization failed (non-critical): $e', name: 'runvision');
395	        // Continue even if time sync fails
396	      }
397	
398	      // Initialize characteristics by reading them once
399	      try {
400	        print('=== [ILENS CONNECT] Reading current settings from device...');
401	
402	        if (_hibernationTimeChar != null) {
403	          final hibTime = await _hibernationTimeChar!.read();
404	          print('=== [ILENS CONNECT] ✓ Hibernation: $hibTime');
405	        }
406	        if (_brightnessChar != null) {
407	          final brightness = await _brightnessChar!.read();
408	          print('=== [ILENS CONNECT] ✓ Brightness: $brightness');
409	        }
410	      } catch (e) {
411	        print('=== [ILENS CONNECT] ⚠️ Settings read failed (non-critical): $e');
412	      }
413	
414	      // NOTE: Time synchronization is now done in provider after Universal Subscriptions init
415	      // Official iLens app sends time sync AFTER initialization commands
416	      // We must follow the same order to avoid GATT errors
417	
418	      // NOTE: Hibernation time is now managed by ILensSettingsNotifier
419	      // The saved user preference will be applied via applyToDevice() after connection
420	      // This allows users to control the screen timeout from the settings UI
421	
422	      // NOTE: Keep-alive is no longer needed - 60s battery polling serves as keep-alive
423	      // _startKeepAlive();
424	
425	      print('=== [ILENS CONNECT] Connection successful');
426	      developer.log('[ILENS] Connection successful, keep-alive started', name: 'runvision');
427	    } catch (e, stackTrace) {
428	      print('=== [ILENS CONNECT] Connection failed: $e');
429	      print('=== [ILENS CONNECT] Stack trace: $stackTrace');
430	      developer.log('[ILENS] Connection failed: $e', name: 'runvision', stackTrace: stackTrace);
431	      _cleanup();
432	
433	      if (e is Failure) {
434	        rethrow;
435	      }
436	
437	      throw Failure.unexpected(
438	        message: 'iLens connection failed: $e',
439	        stackTrace: stackTrace,
440	      );
441	    }
442	  }
