476	  /// 현재 시간 전송 (iLens BLE V1.0.10 Section 3.3)
477	  ///
478	  /// iLens에 현재 시간을 전송하여 시계를 동기화합니다.
479	  ///
480	  /// [reason] Adjust Reason:
481	  ///   - 0x02: External Reference Time Update (Stage 1 - UI layer)
482	  ///   - 0x03: Change of Time Zone (Stage 2 - RTC sync trigger)
483	  ///
484	  /// Returns: Future<void>
485	  /// Throws: Failure if write fails or characteristic not available
486	  Future<void> sendCurrentTime({int reason = 0x03}) async {
487	    if (_currentTimeChar == null) {
488	      throw const Failure.connection(message: 'Current Time characteristic not available');
489	    }
490	
491	    final now = DateTime.now();
492	    developer.log('[ILENS] Sending current time: ${now.toString()} (reason: 0x${reason.toRadixString(16).padLeft(2, '0')})', name: 'runvision');
493	
494	    final bytes = _encodeCurrentTime(now, reason: reason);
495	
496	    print('=== [ILENS TIME] ⚡ Writing to characteristic: ${_currentTimeChar!.uuid}');
497	    print('=== [ILENS TIME] ⚡ Characteristic properties: write=${_currentTimeChar!.properties.write}, writeWithoutResponse=${_currentTimeChar!.properties.writeWithoutResponse}');
498	
499	    try {
500	      await _currentTimeChar!.write(bytes, withoutResponse: false);
501	      print('=== [ILENS TIME] ✓ Write operation completed without exception');
502	
503	      // Read back to verify
504	      try {
505	        if (_currentTimeChar!.properties.read) {
506	          print('=== [ILENS TIME] 🔍 Reading back to verify...');
507	          final readBytes = await _currentTimeChar!.read();
508	          print('=== [ILENS TIME] 🔍 Read back: ${readBytes.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');
509	        } else {
510	          print('=== [ILENS TIME] ⚠️ Characteristic does not support read, cannot verify');
511	        }
512	      } catch (e) {
513	        print('=== [ILENS TIME] ⚠️ Read back failed: $e');
514	      }
515	
516	      developer.log('[ILENS] Current time sent successfully', name: 'runvision');
517	      print('=== [ILENS TIME] ✓ Time synchronized: ${now.toString()}');
518	    } catch (e) {
519	      print('=== [ILENS TIME] ❌ Write failed: $e');
520	      rethrow;
521	    }
522	  }
