568	  /// Set hibernation time (screen sleep timeout)
569	  ///
570	  /// [seconds] Hibernation time in seconds (UINT16, 0-65535)
571	  ///           - 65535 (0xFFFF): "Never" - screen stays on during workout
572	  ///           - 3: Short timeout after workout ends (UX signal)
573	  ///
574	  /// iLens BLE V1.0.10.pdf Section 3.5: Sleep time setting
575	  /// Format: 2 bytes, little-endian
576	  ///
577	  /// Returns: Future<void>
578	  /// Throws: Failure if write fails or characteristic not available
579	  Future<void> setHibernationTime(int seconds) async {
580	    if (_hibernationTimeChar == null) {
581	      throw const Failure.connection(
582	        message: 'Hibernation Time characteristic not available',
583	      );
584	    }
585	
586	    if (seconds < 0 || seconds > 65535) {
587	      throw Failure.unexpected(
588	        message: 'Hibernation time must be 0-65535 seconds (got: $seconds)',
589	      );
590	    }
591	
592	    try {
593	      // Encode as UINT16 little-endian (2 bytes)
594	      final buffer = Uint8List(2);
595	      final byteData = ByteData.view(buffer.buffer);
596	      byteData.setUint16(0, seconds, Endian.little);
597	
598	      print('=== [ILENS HIBERNATION] Setting hibernation time: ${seconds}s');
599	      print('=== [ILENS HIBERNATION] Bytes: ${buffer.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');
600	      developer.log('[ILENS] Setting hibernation time: ${seconds}s', name: 'runvision');
601	
602	      await _hibernationTimeChar!.write(buffer.toList(), withoutResponse: false);
603	
604	      print('=== [ILENS HIBERNATION] ✓ Hibernation time set successfully');
605	      developer.log('[ILENS] Hibernation time set successfully', name: 'runvision');
606	    } catch (e, stackTrace) {
607	      print('=== [ILENS HIBERNATION] ❌ Write failed: $e');
608	      developer.log('[ILENS] Hibernation time write failed: $e', name: 'runvision', stackTrace: stackTrace);
609	      throw Failure.unexpected(
610	        message: 'Failed to set hibernation time: $e',
611	        stackTrace: stackTrace,
612	      );
613	    }
614	  }
