746	      print('=== [ILENS BRIGHTNESS] Setting brightness: $percent%');
747	      print('=== [ILENS BRIGHTNESS] Bytes: ${buffer.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');
748	      developer.log('[ILENS] Setting brightness: $percent%', name: 'runvision');
749	
750	      await _brightnessChar!.write(buffer.toList(), withoutResponse: false);
751	
752	      print('=== [ILENS BRIGHTNESS] ✓ Brightness set successfully');
753	      developer.log('[ILENS] Brightness set successfully', name: 'runvision');
