849	  /// Queue a BLE write operation to prevent simultaneous writes
850	  Future<void> _queueWrite(Future<void> Function() writeOperation) async {
851	    final completer = Completer<void>();
852	
853	    _writeQueue.add(() async {
854	      try {
855	        await writeOperation();
856	        completer.complete();
857	      } catch (e) {
858	        completer.completeError(e);
859	      }
860	    });
861	
862	    _processWriteQueue();
863	    return completer.future;
864	  }
