866	  /// Process write queue sequentially
867	  Future<void> _processWriteQueue() async {
868	    if (_isProcessingQueue || _writeQueue.isEmpty) return;
869	
870	    _isProcessingQueue = true;
871	    print('=== [ILENS QUEUE] Starting queue processing (${_writeQueue.length} items)');
872	
873	    while (_writeQueue.isNotEmpty) {
874	      final operation = _writeQueue.removeAt(0);
875	      try {
876	        await operation();
877	        print('=== [ILENS QUEUE] ✓ Operation completed');
878	      } catch (e) {
879	        print('=== [ILENS QUEUE] ⚠️ Operation failed: $e');
880	        // Continue processing queue even if one operation fails
881	      }
882	    }
883	
884	    _isProcessingQueue = false;
885	    print('=== [ILENS QUEUE] Queue processing complete');
886	  }
