1100	  /// Poll battery level every 1 second (READ operation)
1101	  Future<void> _subscribeToBattery() async {
1102	    if (_batteryChar == null) {
1103	      print('=== [ILENS BATTERY] Battery characteristic not available, skipping battery monitoring');
1104	      developer.log('[ILENS] Battery characteristic not available, skipping battery monitoring', name: 'runvision');
1105	      return;
1106	    }
1107	
1108	    // Poll battery every 60 seconds via READ operation (reduced from 1s to minimize screen wake-ups)
1109	    _batteryPollTimer?.cancel();
1110	    _batteryPollTimer = Timer.periodic(const Duration(seconds: 60), (_) async {
1111	      // Skip battery polling if screen activity is disabled (for hibernation testing)
1112	      if (!_screenActivityEnabled) {
1113	        return;
1114	      }
1115	
1116	      try {
1117	        final bytes = await _batteryChar!.read();
1118	        if (bytes.isNotEmpty) {
1119	          final status = _parseBatteryStatus(bytes);
1120	          _statusController.add(status);
1121	          developer.log('[ILENS] Battery: ${status.batteryLevel}%', name: 'runvision');
1122	        }
1123	      } catch (e) {
1124	        developer.log('[ILENS] Battery read error: $e', name: 'runvision');
1125	      }
1126	    });
1127	
1128	    // Also read battery immediately on connect
1129	    try {
1130	      final bytes = await _batteryChar!.read();
1131	      if (bytes.isNotEmpty) {
1132	        final status = _parseBatteryStatus(bytes);
1133	        _statusController.add(status);
1134	        print('=== [ILENS BATTERY] Initial battery level: ${status.batteryLevel}%');
1135	      }
1136	    } catch (e) {
1137	      print('=== [ILENS BATTERY] Initial battery read failed: $e');
1138	    }
1139	
1140	    print('=== [ILENS BATTERY] Started 60-second battery polling');
1141	    developer.log('[ILENS] Started 60-second battery polling', name: 'runvision');
1142	  }
