1144	  /// CONFIG 패킷 인코딩 - UI Sorting (Protocol V1.0.10 Section 4.3)
1145	  ///
1146	  /// Packet Structure (21 bytes):
1147	  ///   [0]      Command ID = 0x00 (UI Sorting)
1148	  ///   [1-20]   Data: 10 pairs of (index, type)
1149	  ///            Each pair: index (0-9) + metric type id
1150	  ///            Unused positions: 0xFF (hidden/invalid)
1151	  List<int> _encodeConfig(ILensConfig config) {
1152	    print('=== [ILENS ENCODE] Encoding UI sorting config');
1153	
1154	    // UI sorting packet: 1 byte id + 20 bytes data = 21 bytes total
1155	    final bytes = List<int>.filled(21, 0);
1156	    bytes[0] = 0x00; // UI sorting command
1157	
1158	    // Configure display layout: index 0-9, each with metric type
1159	    // Fill all 10 positions to prevent empty items from showing
1160	    for (int i = 0; i < 10; i++) {
1161	      bytes[1 + (i * 2)] = i; // index (0-9)
1162	
1163	      if (i < config.metrics.length) {
1164	        // Valid metric: use actual metric ID
1165	        bytes[1 + (i * 2) + 1] = config.metrics[i].id;
1166	        print('=== [ILENS ENCODE] Position $i: metric id 0x${config.metrics[i].id.toRadixString(16).padLeft(2, '0')} (${_getMetricName(config.metrics[i].id)})');
1167	      } else {
1168	        // Unused position: set to 0xFF to hide from display
1169	        bytes[1 + (i * 2) + 1] = 0xFF;
1170	        print('=== [ILENS ENCODE] Position $i: HIDDEN (0xFF)');
1171	      }
1172	    }
1173	
1174	    print('=== [ILENS ENCODE] UI sorting packet: ${bytes.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');
1175	    return bytes;
1176	  }
