1188	  /// CURRENT TIME 패킷 인코딩 (iLens BLE V1.0.10 Section 3.3)
1189	  ///
1190	  /// Packet Structure (10 bytes):
1191	  ///   [0-1]  year (UINT16, little-endian)
1192	  ///   [2]    month (UINT8, 1-12)
1193	  ///   [3]    day (UINT8, 1-31)
1194	  ///   [4]    hour (UINT8, 0-23, UTC 기준)
1195	  ///   [5]    minute (UINT8, 0-59)
1196	  ///   [6]    second (UINT8, 0-59)
1197	  ///   [7]    dayOfWeek (UINT8, 1=Mon...7=Sun, 0=Unknown)
1198	  ///   [8]    fraction256 (UINT8, 1/256 second, usually 0)
1199	  ///   [9]    reason (UINT8)
1200	  ///
1201	  /// Two-stage synchronization (per iLens firmware architecture):
1202	  /// Stage 1 (reason=0x02): UTC time → UI layer update
1203	  /// Stage 2 (reason=0x03): UTC time + timezone flag → RTC sync trigger
1204	  ///
1205	  /// [reason] Adjust Reason code (0x02 or 0x03)
1206	  List<int> _encodeCurrentTime(DateTime dateTime, {int reason = 0x03}) {
1207	    // Send LOCAL time with 2-stage sync for proper RTC update
1208	    // Stage 1 (reason 0x02): LOCAL time → UI layer update
1209	    // Stage 2 (reason 0x03): LOCAL time + timezone flag → RTC sync trigger
1210	    final timeToSend = dateTime;  // USE LOCAL, NOT UTC
1211	
1212	    print('=== [ILENS TIME] Local time: ${dateTime.toString()}');
1213	    print('=== [ILENS TIME] Sending LOCAL time (not UTC)');
1214	    print('=== [ILENS TIME] Reason: 0x${reason.toRadixString(16).padLeft(2, '0')} (${reason == 0x02 ? "External Reference" : "Timezone Change"})');
1215	
1216	    final bytes = List<int>.filled(10, 0);
1217	
1218	    // Year (UINT16, little-endian)
1219	    final year = timeToSend.year;
1220	    bytes[0] = year & 0xFF;          // Low byte
1221	    bytes[1] = (year >> 8) & 0xFF;   // High byte
1222	
1223	    // Month (1-12)
1224	    bytes[2] = timeToSend.month;
1225	
1226	    // Day (1-31)
1227	    bytes[3] = timeToSend.day;
1228	
1229	    // Hour (0-23, LOCAL)
1230	    bytes[4] = timeToSend.hour;
1231	
1232	    // Minute (0-59)
1233	    bytes[5] = timeToSend.minute;
1234	
1235	    // Second (0-59)
1236	    bytes[6] = timeToSend.second;
1237	
1238	    // DayOfWeek (1=Mon, 2=Tue, ..., 7=Sun)
1239	    // DateTime.weekday: 1=Mon, 7=Sun (same as BLE standard)
1240	    bytes[7] = timeToSend.weekday;
1241	
1242	    // Fraction256 (1/256 second, set to 0)
1243	    bytes[8] = 0x00;
1244	
1245	    // Reason (0x02 or 0x03)
1246	    bytes[9] = reason;
1247	
1248	    print('=== [ILENS TIME] Time packet: ${bytes.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');
1249	    print('=== [ILENS TIME] Year: $year, Month: ${timeToSend.month}, Day: ${timeToSend.day}');
1250	    print('=== [ILENS TIME] LOCAL Time: ${timeToSend.hour}:${timeToSend.minute}:${timeToSend.second}, DayOfWeek: ${timeToSend.weekday}');
1251	
1252	    return bytes;
1253	  }
1254	
1255	  /// METRIC 패킷 인코딩 - Exercise Data (Protocol V1.0.10 Section 4.3)
1256	  ///
1257	  /// Packet Structure (5 bytes):
1258	  ///   [0]     Metric ID (UINT8)
1259	  ///           0x02 = Calories (kcal)
1260	  ///           0x06 = Distance (cm) - 100을 곱해서 소숫점 두 자리 보존
1261	  ///           0x07 = Speed (km/h * 10) - 10을 곱해서 소숫점 한 자리 보존
1262	  ///           0x0B = Heart Rate (bpm)
1263	  ///           0x0E = Cadence (spm)
1264	  ///   [1-4]   Value (UINT32, Little-Endian)
1265	  List<int> _encodeMetric(ILensMetric metric) {
1266	    print('=== [ILENS ENCODE] Encoding metric - Type: 0x${metric.type.id.toRadixString(16).padLeft(2, '0')}, Value: ${metric.value}');
1267	
1268	    // Exercise data packet: 1 byte id + 4 bytes data = 5 bytes total
1269	    final bytes = List<int>.filled(5, 0);
1270	    bytes[0] = metric.type.id;
1271	
1272	    // Convert value to UINT32
1273	    // Per iLens BLE V1.0.10 PDF Section 4.3:
1274	    // - distance (0x06): UINT32, Unit: meters (정수로 반올림)
1275	    // - velocity (0x07): UINT32, Unit: km/h (정수로 반올림)
1276	    // - calories (0x02): UINT32, Unit: kcal (정수로 반올림)
1277	    // - All other metrics: UINT32, round to integer
1278	    //
1279	    // NOTE: iLens 하드웨어가 소숫점 표시를 지원하는지 확인 필요
1280	    // 현재는 프로토콜 문서대로 정수 값만 전송
1281	    final value = metric.value.round().clamp(0, 4294967295);
1282	    print('=== [ILENS ENCODE] ${metric.type.toString()}: ${metric.value.toStringAsFixed(2)} → $value (rounded to integer)');
1283	
1284	    // Encode as UINT32 little-endian
1285	    final byteData = ByteData(4);
1286	    byteData.setUint32(0, value, Endian.little);
1287	    bytes[1] = byteData.getUint8(0);
1288	    bytes[2] = byteData.getUint8(1);
1289	    bytes[3] = byteData.getUint8(2);
1290	    bytes[4] = byteData.getUint8(3);
1291	
1292	    print('=== [ILENS ENCODE] Metric packet: ${bytes.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');
1293	    return bytes;
1294	  }
1295	
1296	  /// BATTERY 패킷 파싱 (iLens BLE V1.0.10.pdf Section 3.2)
1297	  ///
1298	  /// Battery Level: UINT8 (0-100)
1299	  /// [bytes] Battery READ 바이트
1300	  /// Returns: ILensStatus
1301	  ILensStatus _parseBatteryStatus(List<int> bytes) {
1302	    print('=== [ILENS BATTERY] Raw bytes: ${bytes.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');
1303	
1304	    // Battery is simple UINT8 (0-100)
1305	    int batteryLevel = 0;
1306	    if (bytes.isNotEmpty) {
1307	      batteryLevel = bytes[0].clamp(0, 100);
1308	      _lastBatteryLevel = batteryLevel;
1309	      print('=== [ILENS BATTERY] Battery level: $batteryLevel%');
1310	    }
1311	
1312	    return ILensStatus(
1313	      isConnected: true,  // We're reading battery, so we're connected
1314	      batteryLevel: batteryLevel,
1315	      timestamp: DateTime.now(),
1316	      firmwareVersion: _firmwareVersion,
1317	    );
1318	  }
1319	
1320	  /// Keep-alive 타이머 시작
1321	  void _startKeepAlive() {
1322	    _stopKeepAlive();
1323	
1324	    print('=== [ILENS KEEPALIVE] Starting keep-alive timer (${_keepAliveInterval.inSeconds}s interval)');
1325	    developer.log('[ILENS] Starting keep-alive timer', name: 'runvision');
1326	
1327	    _keepAliveTimer = Timer.periodic(_keepAliveInterval, (timer) async {
1328	      // Skip keep-alive if screen activity is disabled (for hibernation testing)
1329	      if (!_screenActivityEnabled) {
1330	        return;
1331	      }
1332	
1333	      if (_batteryChar != null && _connectedDevice != null) {
1334	        try {
1335	          // Read battery characteristic to keep connection alive
1336	          print('=== [ILENS KEEPALIVE] Sending keep-alive request');
1337	          await _batteryChar!.read();
1338	          print('=== [ILENS KEEPALIVE] Keep-alive successful');
1339	        } catch (e) {
1340	          print('=== [ILENS KEEPALIVE] Keep-alive failed: $e');
1341	          developer.log('[ILENS] Keep-alive failed: $e', name: 'runvision');
1342	        }
1343	      }
1344	    });
1345	  }
1346	
1347	  /// Keep-alive 타이머 중지
1348	  void _stopKeepAlive() {
1349	    _keepAliveTimer?.cancel();
1350	    _keepAliveTimer = null;
1351	    print('=== [ILENS KEEPALIVE] Keep-alive timer stopped');
1352	  }
1353	
1354	  /// 연결 해제 처리 (자동 재연결 포함)
1355	  void _handleDisconnection() {
1356	    print('=== [ILENS RECONNECT] Handling disconnection, auto-reconnect=$_autoReconnectEnabled, attempts=$_reconnectAttempts');
1357	
1358	    if (_autoReconnectEnabled &&
1359	        _reconnectAttempts < _maxReconnectAttempts &&
1360	        _lastDeviceId != null) {
1361	      _reconnectAttempts++;
1362	      print('=== [ILENS RECONNECT] Attempting reconnection $_reconnectAttempts/$_maxReconnectAttempts');
1363	      developer.log('[ILENS] Attempting reconnection $_reconnectAttempts/$_maxReconnectAttempts', name: 'runvision');
1364	
1365	      // Wait before reconnecting (exponential backoff)
1366	      Future.delayed(Duration(seconds: 2 * _reconnectAttempts), () async {
1367	        try {
1368	          if (_autoReconnectEnabled && _lastDeviceId != null) {
1369	            print('=== [ILENS RECONNECT] Reconnecting to $_lastDeviceId');
1370	            await connect(_lastDeviceId!);
1371	            print('=== [ILENS RECONNECT] Reconnection successful');
1372	            developer.log('[ILENS] Reconnection successful', name: 'runvision');
1373	          }
1374	        } catch (e) {
1375	          print('=== [ILENS RECONNECT] Reconnection failed: $e');
1376	          developer.log('[ILENS] Reconnection failed: $e', name: 'runvision');
1377	          _cleanup();
1378	        }
1379	      });
1380	    } else {
1381	      print('=== [ILENS RECONNECT] Max reconnection attempts reached or auto-reconnect disabled');
1382	      developer.log('[ILENS] Max reconnection attempts reached', name: 'runvision');
1383	      _cleanup();
1384	    }
1385	  }
1386	
1387	  /// 리소스 정리
1388	  void _cleanup() {
1389	    _stopKeepAlive();
1390	    _batteryPollTimer?.cancel();
1391	    _batterySubscription?.cancel();
1392	    _deviceStateSubscription?.cancel();
1393	
1394	    _batteryPollTimer = null;
1395	    _batterySubscription = null;
1396	    _deviceStateSubscription = null;
1397	
