import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:flutter_blue_plus/flutter_blue_plus.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:runvision/features/ilens/data/datasources/ilens_ble_datasource.dart';
import 'package:runvision/features/ilens/domain/entities/ilens_types.dart';

/// iLens BLE DataSource Provider
final ilensDataSourceProvider = Provider<ILensBleDataSource>((ref) {
  return ILensBleDataSource();
});

/// iLens 상태 스트림 Provider
final ilensStatusProvider = StreamProvider<ILensStatus>((ref) {
  final dataSource = ref.watch(ilensDataSourceProvider);
  return dataSource.statusStream;
});

/// iLens 스캔된 기기 목록 Provider
final ilensScannedDevicesProvider = StateNotifierProvider<ILensScannedDevicesNotifier, List<BluetoothDevice>>((ref) {
  return ILensScannedDevicesNotifier(ref);
});

/// iLens 연결 상태 Provider
final ilensConnectionStateProvider = StateProvider<bool>((ref) => false);

/// iLens 연결된 기기 Provider
final ilensConnectedDeviceProvider = StateProvider<BluetoothDevice?>((ref) => null);

/// iLens 연결된 기기명 Provider (저장된 이름 사용)
final ilensConnectedDeviceNameProvider = StateProvider<String?>((ref) => null);

/// iLens 스캔 상태 Provider
final ilensScanningStateProvider = StateProvider<bool>((ref) => false);

/// iLens Scanned Devices Notifier
class ILensScannedDevicesNotifier extends StateNotifier<List<BluetoothDevice>> {
  final Ref ref;

  ILensScannedDevicesNotifier(this.ref) : super([]);

  Future<void> startScan() async {
    // 스캔 시작 상태 표시
    ref.read(ilensScanningStateProvider.notifier).state = true;

    try {
      final dataSource = ref.read(ilensDataSourceProvider);
      final devices = await dataSource.scanForDevices(timeout: const Duration(seconds: 5));
      state = devices;
    } finally {
      // 스캔 종료 상태 표시
      ref.read(ilensScanningStateProvider.notifier).state = false;
    }
  }

  Future<void> connect(String deviceId) async {
    final dataSource = ref.read(ilensDataSourceProvider);

    // 연결 시작 - 스캔 상태 표시
    ref.read(ilensScanningStateProvider.notifier).state = true;

    try {
      print('=== [ILENS NOTIFIER] Starting connection to $deviceId');
      await dataSource.connect(deviceId);
      print('=== [ILENS NOTIFIER] Connection successful');

      // 연결 상태 확인
      final isConnected = dataSource.isConnected;
      print('=== [ILENS NOTIFIER] Connection state check: $isConnected');

      // 연결 성공 시에만 설정 전송
      if (isConnected) {
        // 연결된 기기 정보 저장
        final connectedDevice = state.where((d) => d.remoteId.str == deviceId).firstOrNull;
        if (connectedDevice != null) {
          ref.read(ilensConnectedDeviceProvider.notifier).state = connectedDevice;
          print('=== [ILENS NOTIFIER] Connected device saved: ${connectedDevice.platformName.isEmpty ? deviceId : connectedDevice.platformName}');
        }

        // NOTE: Time sync is now done in connect() AFTER Universal Subscriptions init
        // This ensures proper initialization order

        // CRITICAL: Do NOT send config write immediately after connection!
        // Official iLens app doesn't write to exercise characteristic until running session starts
        // Immediate config write interferes with BLE stack and causes GATT_ERROR on settings writes
        // Config will be sent when running session actually starts (not implemented yet)
        print('=== [ILENS NOTIFIER] Skipping config write (will send when session starts)');

        // Provider 상태 업데이트 (UI 활성화)
        ref.read(ilensConnectionStateProvider.notifier).state = true;
        ref.read(ilensScanningStateProvider.notifier).state = false;
        print('=== [ILENS NOTIFIER] ✓ Connection complete, UI activated');

        // 예기치 않은 연결 끊김 시 UI를 검색화면으로 전환
        dataSource.onDisconnected = () {
          ref.read(ilensConnectionStateProvider.notifier).state = false;
          ref.read(ilensConnectedDeviceProvider.notifier).state = null;
          ref.read(ilensConnectedDeviceNameProvider.notifier).state = null;
          print('=== [ILENS NOTIFIER] Unexpected disconnect — UI reset to search screen');
        };
      } else {
        print('=== [ILENS NOTIFIER] ⚠️ Connection reported success but isConnected is false');
        ref.read(ilensConnectionStateProvider.notifier).state = false;
        ref.read(ilensScanningStateProvider.notifier).state = false;
      }
    } catch (e) {
      print('=== [ILENS NOTIFIER] ❌ Connection failed: $e');
      ref.read(ilensConnectionStateProvider.notifier).state = false;
      ref.read(ilensScanningStateProvider.notifier).state = false;
      rethrow;
    }
  }

  Future<void> disconnect() async {
    final dataSource = ref.read(ilensDataSourceProvider);
    await dataSource.disconnect();
    ref.read(ilensConnectionStateProvider.notifier).state = false;
    ref.read(ilensConnectedDeviceProvider.notifier).state = null;
    ref.read(ilensConnectedDeviceNameProvider.notifier).state = null;
    state = [];
    print('=== [ILENS NOTIFIER] Disconnected and cleared device info');
  }
}

/// iLens Settings State Provider
final ilensSettingsProvider = StateNotifierProvider<ILensSettingsNotifier, ILensSettings>((ref) {
  return ILensSettingsNotifier(ref);
});

/// iLens 밝기 조절 가능 여부 Provider
final ilensBrightnessAvailableProvider = Provider<bool>((ref) {
  final dataSource = ref.watch(ilensDataSourceProvider);
  final isConnected = ref.watch(ilensConnectionStateProvider);
  return isConnected && dataSource.isBrightnessAvailable;
});

/// iLens Settings Notifier
class ILensSettingsNotifier extends StateNotifier<ILensSettings> {
  final Ref ref;
  static const String _keyBrightness = 'ilens_brightness';
  static const String _keyHibernation = 'ilens_hibernation';
  static const String _keyScreenOffTime = 'ilens_screen_off_time';

  ILensSettingsNotifier(this.ref) : super(const ILensSettings()) {
    _loadSavedSettings();
  }

  /// Load saved settings from SharedPreferences
  Future<void> _loadSavedSettings() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final brightness = prefs.getInt(_keyBrightness) ?? 30;
      final hibernation = prefs.getInt(_keyHibernation) ?? 60;
      final screenOffTime = prefs.getInt(_keyScreenOffTime) ?? 60;
      state = ILensSettings(
        brightness: brightness,
        hibernationSeconds: hibernation,
        screenOffTime: screenOffTime,
      );
      print('[ILENS SETTINGS] Loaded saved settings: brightness=$brightness, hibernation=$hibernation, screenOffTime=$screenOffTime');
    } catch (e) {
      print('[ILENS SETTINGS] Failed to load saved settings: $e');
    }
  }

  /// Read current settings from connected device
  Future<void> readFromDevice() async {
    final dataSource = ref.read(ilensDataSourceProvider);
    if (!dataSource.isConnected) return;

    try {
      int brightness = state.brightness;
      int hibernation = state.hibernationSeconds;
      int screenOffTime = state.screenOffTime;

      // Read hibernation time first (more reliable than brightness)
      try {
        hibernation = await dataSource.getHibernationTime()
            .timeout(const Duration(seconds: 3));
        print('[ILENS SETTINGS] ✓ Hibernation read: $hibernation seconds');
      } catch (e) {
        print('[ILENS SETTINGS] Failed to read hibernation: $e');
      }

      // Add delay between BLE read operations to prevent GATT errors
      await Future.delayed(const Duration(milliseconds: 300));

      // Read Screen OFF Time (자동깨우기)
      try {
        screenOffTime = await dataSource.getScreenOffTime()
            .timeout(const Duration(seconds: 3));
        print('[ILENS SETTINGS] ✓ Screen OFF Time read: $screenOffTime seconds');
      } catch (e) {
        print('[ILENS SETTINGS] Failed to read Screen OFF Time: $e');
      }

      await Future.delayed(const Duration(milliseconds: 300));

      // Read brightness if available (with short timeout to prevent connection issues)
      if (dataSource.isBrightnessAvailable) {
        try {
          brightness = await dataSource.getBrightness()
              .timeout(const Duration(seconds: 2));
          print('[ILENS SETTINGS] ✓ Brightness read: $brightness%');
        } catch (e) {
          print('[ILENS SETTINGS] Brightness read timeout/failed (keeping saved value=$brightness%): $e');
          // Keep using saved brightness value - this is OK
        }
      }

      state = ILensSettings(
        brightness: brightness,
        hibernationSeconds: hibernation,
        screenOffTime: screenOffTime,
      );

      // Save to preferences
      await _saveSettings();
      print('[ILENS SETTINGS] Read from device: brightness=$brightness, hibernation=$hibernation, screenOffTime=$screenOffTime');
    } catch (e) {
      print('[ILENS SETTINGS] Failed to read from device: $e');
    }
  }

  /// Set brightness and persist
  Future<void> setBrightness(int percent) async {
    final dataSource = ref.read(ilensDataSourceProvider);

    try {
      await dataSource.setBrightness(percent);
      state = state.copyWith(brightness: percent);
      await _saveSettings();
      print('[ILENS SETTINGS] Brightness set to $percent%');
    } catch (e) {
      print('[ILENS SETTINGS] Failed to set brightness: $e');
      rethrow;
    }
  }

  /// Set hibernation time and persist
  Future<void> setHibernationTime(int seconds) async {
    print('[ILENS SETTINGS] setHibernationTime called with $seconds seconds');
    final dataSource = ref.read(ilensDataSourceProvider);
    print('[ILENS SETTINGS] dataSource.isConnected: ${dataSource.isConnected}');

    try {
      print('[ILENS SETTINGS] Calling dataSource.setHibernationTime($seconds)...');
      await dataSource.setHibernationTime(seconds);
      print('[ILENS SETTINGS] dataSource.setHibernationTime completed');
      state = state.copyWith(hibernationSeconds: seconds);
      await _saveSettings();
      print('[ILENS SETTINGS] Hibernation time set to ${seconds}s');
    } catch (e) {
      print('[ILENS SETTINGS] Failed to set hibernation: $e');
      rethrow;
    }
  }

  /// Set Screen OFF Time (자동깨우기) and persist
  Future<void> setScreenOffTime(int seconds) async {
    print('[ILENS SETTINGS] setScreenOffTime called with $seconds seconds');
    final dataSource = ref.read(ilensDataSourceProvider);

    try {
      await dataSource.setScreenOffTime(seconds);
      state = state.copyWith(screenOffTime: seconds);
      await _saveSettings();
      print('[ILENS SETTINGS] Screen OFF time set to ${seconds}s');
    } catch (e) {
      print('[ILENS SETTINGS] Failed to set screen OFF time: $e');
      rethrow;
    }
  }

  /// Update state without sending to device (for UI responsiveness)
  void updateBrightnessLocal(int percent) {
    state = state.copyWith(brightness: percent);
  }

  /// Save settings to SharedPreferences
  Future<void> _saveSettings() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setInt(_keyBrightness, state.brightness);
      await prefs.setInt(_keyHibernation, state.hibernationSeconds);
      await prefs.setInt(_keyScreenOffTime, state.screenOffTime);
    } catch (e) {
      print('[ILENS SETTINGS] Failed to save settings: $e');
    }
  }

  /// Apply saved settings to connected device
  Future<void> applyToDevice() async {
    final dataSource = ref.read(ilensDataSourceProvider);
    if (!dataSource.isConnected) return;

    try {
      // Apply brightness if available
      if (dataSource.isBrightnessAvailable) {
        await dataSource.setBrightness(state.brightness);
      }
      // Apply hibernation time
      await dataSource.setHibernationTime(state.hibernationSeconds);
      // Apply Screen OFF Time (자동깨우기)
      await dataSource.setScreenOffTime(state.screenOffTime);
      print('[ILENS SETTINGS] Applied settings to device');
    } catch (e) {
      print('[ILENS SETTINGS] Failed to apply settings: $e');
    }
  }
}

