260	    function compute(info as Activity.Info) as Void {
261	        // Passive Connection 타임아웃 (3초)
262	        if (_scanStatus.equals("PASSIVE") && !_isConnected && _elapsedSeconds >= 3) {
263	            try {
264	                // FR55 호환성: has 연산자로 API 존재 여부 확인
265	                if (_connectedDevice != null && (BluetoothLowEnergy has :unpairDevice)) {
266	                    BluetoothLowEnergy.unpairDevice(_connectedDevice);
267	                }
268	                _connectedDevice = null;
269	                _profileRegistered = false;
270	                BluetoothLowEnergy.registerProfile(getExerciseProfile());
271	                _scanStatus = "RESCAN";
272	                addBleLog("RESCAN");
273	            } catch (ex) {
274	                addBleLog("ERR:rescan");
275	            }
276	        }
277	
278	        // ✅ Pairing 타임아웃 (Connecting 상태 멈춤 방지)
279	        // System.getTimer() 사용 - 액티비티 시작 전에도 동작
280	        if (_pairingStartTime > 0 && !_isConnected) {
281	            var pairingDuration = System.getTimer() - _pairingStartTime;
282	            if (pairingDuration >= PAIRING_TIMEOUT_MS) {
283	                _pairingRetryCount++;
284	                addBleLog("PAIR_TO:" + _pairingRetryCount);  // Pairing Timeout + retry count
285	                _pairingStartTime = 0;
286	
287	                try {
288	                    if (_connectedDevice != null && (BluetoothLowEnergy has :unpairDevice)) {
289	                        BluetoothLowEnergy.unpairDevice(_connectedDevice);
290	                    }
291	                    _connectedDevice = null;
292	                    _isReconnecting = false;
293	                } catch (ex) {
294	                    // 무시
295	                }
296	
297	                if (_pairingRetryCount >= PAIRING_MAX_RETRIES) {
298	                    // 3회 실패 → CONN_ERR
299	                    _scanStatus = "CONN_ERR";
300	                    _pairingRetryCount = 0;
301	                    addBleLog("CONN_ERR");
302	                } else {
303	                    // 재시도: 즉시 다시 pairing
304	                    _scanStatus = "RETRY " + _pairingRetryCount;
305	                    if (_lastScanResult != null) {
306	                        try {
307	                            _pairingStartTime = System.getTimer();
308	                            _connectedDevice = BluetoothLowEnergy.pairDevice(_lastScanResult);
309	                            if (_connectedDevice == null) {
310	                                _pairingStartTime = 0;
311	                            }
312	                        } catch (ex) {
313	                            _pairingStartTime = 0;
314	                        }
315	                    }
316	                }
317	            }
318	        }
