320	        // Auto-reconnect (연결 끊김 시)
321	        // 전략: 1-5회는 5초 간격 단순 재연결, 6회째 unpair 후 재스캔, 이후 1분마다 재스캔
322	        if (_needsReconnect && !_isConnected && !_isReconnecting) {
323	            var timeSinceLastTry = _elapsedSeconds - _lastReconnectTime;
324	            var shouldTry = false;
325	            var interval = 0;
326	
327	            if (_reconnectAttempts < RECONNECT_FAST_MAX) {
328	                // 1-5회: 5초 간격
329	                interval = RECONNECT_FAST_INTERVAL;
330	                shouldTry = (timeSinceLastTry >= interval);
331	            } else {
332	                // 6회 이후: 1분 간격
