import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import '../providers/ilens_providers.dart';
import '../../domain/entities/ilens_types.dart';

enum _ScreenMode { half, full, short, custom }

class _ModePreset {
  final String label;
  final int hibernation;
  final int screenOff;
  final String battery;
  final String onTimeText;
  final String cycleText;

  const _ModePreset({
    required this.label,
    required this.hibernation,
    required this.screenOff,
    required this.battery,
    required this.onTimeText,
    required this.cycleText,
  });
}

class ILensSettingsCard extends ConsumerStatefulWidget {
  const ILensSettingsCard({super.key});

  @override
  ConsumerState<ILensSettingsCard> createState() => _ILensSettingsCardState();
}

class _ILensSettingsCardState extends ConsumerState<ILensSettingsCard> {
  static const _presets = {
    _ScreenMode.short: _ModePreset(
      label: '단거리',
      hibernation: 65535,
      screenOff: 0,
      battery: '약 80분',
      onTimeText: '항상',
      cycleText: '—',
    ),
    _ScreenMode.half: _ModePreset(
      label: '하프코스',
      hibernation: 10,
      screenOff: 30,
      battery: '약 4시간',
      onTimeText: '10초',
      cycleText: '30초',
    ),
    _ScreenMode.full: _ModePreset(
      label: '풀코스',
      hibernation: 5,
      screenOff: 60,
      battery: '약 8시간',
      onTimeText: '5초',
      cycleText: '60초',
    ),
  };

  final _onTimeController = TextEditingController();
  final _cycleController = TextEditingController();
  final _onTimeFocus = FocusNode();
  final _cycleFocus = FocusNode();
  bool _forceCustomMode = false;

  @override
  void initState() {
    super.initState();
    _onTimeFocus.addListener(_scrollToFocused);
    _cycleFocus.addListener(_scrollToFocused);
    WidgetsBinding.instance.addPostFrameCallback((_) {
      final settings = ref.read(ilensSettingsProvider);
      if (_detectMode(settings) == _ScreenMode.custom) {
        setState(() => _forceCustomMode = true);
      }
    });
  }

  void _scrollToFocused() {
    if (_onTimeFocus.hasFocus || _cycleFocus.hasFocus) {
      Future.delayed(const Duration(milliseconds: 300), () {
        if (mounted) {
          Scrollable.ensureVisible(
            context,
            duration: const Duration(milliseconds: 300),
            alignment: 0.8,
          );
        }
      });
    }
  }

  @override
  void dispose() {
    _onTimeFocus.removeListener(_scrollToFocused);
    _cycleFocus.removeListener(_scrollToFocused);
    _onTimeController.dispose();
    _cycleController.dispose();
    _onTimeFocus.dispose();
    _cycleFocus.dispose();
    super.dispose();
  }

  _ScreenMode _detectMode(ILensSettings settings) {
    if (settings.hibernationSeconds == 65535) return _ScreenMode.short;
    if (settings.hibernationSeconds == 10 && settings.screenOffTime == 30) return _ScreenMode.half;
    if (settings.hibernationSeconds == 5 && settings.screenOffTime == 60) return _ScreenMode.full;
    return _ScreenMode.custom;
  }

  _ScreenMode _currentMode(ILensSettings settings) {
    if (_forceCustomMode) return _ScreenMode.custom;
    return _detectMode(settings);
  }

  @override
  Widget build(BuildContext context) {
    final settings = ref.watch(ilensSettingsProvider);
    final ilensConnected = ref.watch(ilensConnectionStateProvider);
    final brightnessAvailable = ref.watch(ilensBrightnessAvailableProvider);

    if (!ilensConnected) return const SizedBox.shrink();

    final screenWidth = MediaQuery.of(context).size.width;
    final isSmallScreen = screenWidth < 360;
    final isLargeScreen = screenWidth > 400;
    final labelFontSize = isSmallScreen ? 13.0 : (isLargeScreen ? 16.0 : 14.0);
    final valueFontSize = isSmallScreen ? 14.0 : (isLargeScreen ? 18.0 : 16.0);
    final chipFontSize = isSmallScreen ? 11.0 : (isLargeScreen ? 14.0 : 12.0);
    final iconSize = isSmallScreen ? 18.0 : (isLargeScreen ? 24.0 : 20.0);
    final horizontalPadding = isSmallScreen ? 12.0 : 16.0;

    return Card(
      margin: EdgeInsets.symmetric(horizontal: horizontalPadding, vertical: 8),
      child: Padding(
        padding: EdgeInsets.all(horizontalPadding),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          mainAxisSize: MainAxisSize.min,
          children: [
            if (brightnessAvailable) ...[
              _buildBrightnessSection(
                settings: settings,
                labelFontSize: labelFontSize,
                valueFontSize: valueFontSize,
                chipFontSize: chipFontSize,
                iconSize: iconSize,
                isSmallScreen: isSmallScreen,
              ),
              SizedBox(height: isSmallScreen ? 16 : 24),
            ],
            _buildScreenModeSection(
              settings: settings,
              labelFontSize: labelFontSize,
              valueFontSize: valueFontSize,
              chipFontSize: chipFontSize,
              iconSize: iconSize,
              isSmallScreen: isSmallScreen,
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildBrightnessSection({
    required ILensSettings settings,
    required double labelFontSize,
    required double valueFontSize,
    required double chipFontSize,
    required double iconSize,
    required bool isSmallScreen,
  }) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Row(
          children: [
            Icon(Icons.brightness_6, size: iconSize, color: Colors.amber),
            SizedBox(width: isSmallScreen ? 6 : 8),
            Text('밝기', style: TextStyle(fontSize: labelFontSize, fontWeight: FontWeight.bold)),
            const Spacer(),
            Text('${settings.brightness}%', style: TextStyle(fontSize: valueFontSize, fontWeight: FontWeight.bold)),
          ],
        ),
        SizedBox(height: isSmallScreen ? 4 : 8),
        SliderTheme(
          data: SliderTheme.of(context).copyWith(
            thumbShape: RoundSliderThumbShape(enabledThumbRadius: isSmallScreen ? 10 : 12),
            overlayShape: RoundSliderOverlayShape(overlayRadius: isSmallScreen ? 20 : 24),
          ),
          child: Slider(
            value: settings.brightness.toDouble(),
            min: 0,
            max: 100,
            divisions: 20,
            label: '${settings.brightness}%',
            onChanged: (value) {
              ref.read(ilensSettingsProvider.notifier).updateBrightnessLocal(value.round());
            },
            onChangeEnd: (value) async {
              try {
                await ref.read(ilensSettingsProvider.notifier).setBrightness(value.round());
              } catch (e) {
                await Future.delayed(const Duration(milliseconds: 200));
                if (mounted && ref.read(ilensConnectionStateProvider)) {
                  ScaffoldMessenger.of(context).showSnackBar(
                    const SnackBar(content: Text('밝기 설정 실패. 다시 시도해주세요'), backgroundColor: Colors.red),
                  );
                }
              }
            },
          ),
        ),
        Wrap(
          spacing: isSmallScreen ? 4 : 8,
          runSpacing: 4,
          alignment: WrapAlignment.spaceEvenly,
          children: [
            _buildBrightnessPreset('30%', 30, settings.brightness, chipFontSize, isSmallScreen),
            _buildBrightnessPreset('50%', 50, settings.brightness, chipFontSize, isSmallScreen),
            _buildBrightnessPreset('75%', 75, settings.brightness, chipFontSize, isSmallScreen),
            _buildBrightnessPreset('100%', 100, settings.brightness, chipFontSize, isSmallScreen),
          ],
        ),
      ],
    );
  }

  Widget _buildScreenModeSection({
    required ILensSettings settings,
    required double labelFontSize,
    required double valueFontSize,
    required double chipFontSize,
    required double iconSize,
    required bool isSmallScreen,
  }) {
    final mode = _currentMode(settings);
    final modeLabel = mode == _ScreenMode.custom ? '사용자정의' : _presets[mode]!.label;

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Row(
          children: [
            Icon(Icons.monitor, size: iconSize, color: Colors.blueGrey),
            SizedBox(width: isSmallScreen ? 6 : 8),
            Text('화면 동작', style: TextStyle(fontSize: labelFontSize, fontWeight: FontWeight.bold)),
            const Spacer(),
            Text(
              modeLabel,
              style: TextStyle(fontSize: labelFontSize, color: Colors.blue, fontWeight: FontWeight.w600),
            ),
          ],
        ),
        SizedBox(height: isSmallScreen ? 8 : 12),
        Wrap(
          spacing: isSmallScreen ? 4 : 8,
          runSpacing: 4,
          children: [
            _buildModeChip(_ScreenMode.half, mode, chipFontSize, isSmallScreen),
            _buildModeChip(_ScreenMode.full, mode, chipFontSize, isSmallScreen),
            _buildModeChip(_ScreenMode.short, mode, chipFontSize, isSmallScreen),
            _buildCustomChip(mode, chipFontSize, isSmallScreen),
          ],
        ),
        SizedBox(height: isSmallScreen ? 12 : 16),
        if (mode != _ScreenMode.custom)
          _buildModeDetails(
            preset: _presets[mode]!,
            labelFontSize: labelFontSize,
            valueFontSize: valueFontSize,
            isSmallScreen: isSmallScreen,
          )
        else
          _buildCustomDetails(
            settings: settings,
            labelFontSize: labelFontSize,
            chipFontSize: chipFontSize,
            isSmallScreen: isSmallScreen,
          ),
      ],
    );
  }

  Widget _buildModeChip(_ScreenMode mode, _ScreenMode current, double fontSize, bool isSmall) {
    final preset = _presets[mode]!;
    final isSelected = mode == current;
    return ChoiceChip(
      label: Text(preset.label, style: TextStyle(fontSize: fontSize)),
      selected: isSelected,
      onSelected: (selected) {
        if (selected) {
          setState(() => _forceCustomMode = false);
          _applyPreset(preset);
        }
      },
      selectedColor: Colors.blue.shade100,
      padding: isSmall ? const EdgeInsets.symmetric(horizontal: 4) : null,
      materialTapTargetSize: MaterialTapTargetSize.shrinkWrap,
      visualDensity: isSmall ? VisualDensity.compact : null,
    );
  }

  Widget _buildCustomChip(_ScreenMode current, double fontSize, bool isSmall) {
    final isSelected = current == _ScreenMode.custom;
    return ChoiceChip(
      label: Text('사용자정의', style: TextStyle(fontSize: fontSize)),
      selected: isSelected,
      onSelected: (selected) {
        if (selected) setState(() => _forceCustomMode = true);
      },
      selectedColor: Colors.blue.shade100,
      padding: isSmall ? const EdgeInsets.symmetric(horizontal: 4) : null,
      materialTapTargetSize: MaterialTapTargetSize.shrinkWrap,
      visualDensity: isSmall ? VisualDensity.compact : null,
    );
  }

  Widget _buildModeDetails({
