        ),
        SizedBox(height: isSmallScreen ? 12 : 16),
        Row(
          children: [
            Icon(Icons.battery_charging_full, size: 16, color: Colors.green.shade600),
            const SizedBox(width: 4),
            Text(preset.battery, style: const TextStyle(fontWeight: FontWeight.w500)),
          ],
        ),
        SizedBox(height: isSmallScreen ? 4 : 8),
        Text(
          '※ 화면 밝기와 주변 기온에 따라 달라질 수 있습니다',
          style: TextStyle(fontSize: 11, color: Colors.grey.shade500),
        ),
      ],
