  Widget _buildCustomDetails({
    required ILensSettings settings,
    required double labelFontSize,
    required double chipFontSize,
    required bool isSmallScreen,
  }) {
    final currentOnTime = settings.hibernationSeconds == 65535
        ? '항상'
        : '${settings.hibernationSeconds}초';
    final currentCycle = '${settings.screenOffTime}초';
    final battery = _estimateBattery(settings.hibernationSeconds, settings.screenOffTime);

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Row(
          children: [
            Expanded(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text('화면 ON 시간', style: TextStyle(fontSize: labelFontSize, color: Colors.grey.shade600)),
                  Text('현재 $currentOnTime', style: TextStyle(fontSize: chipFontSize, color: Colors.grey)),
                ],
              ),
            ),
            SizedBox(
              width: 100,
              height: 40,
              child: TextField(
                controller: _onTimeController,
                focusNode: _onTimeFocus,
                keyboardType: TextInputType.number,
                textAlignVertical: TextAlignVertical.center,
                decoration: InputDecoration(
                  hintText: '예: 10',
