  String _estimateBattery(int hibernation, int screenOff) {
    if (hibernation == 65535) return '약 80분';
    final total = hibernation + screenOff;
    if (total == 0) return '—';
    final dutyPct = hibernation * 100 / total;
    if (dutyPct >= 80) return '약 1.5시간';
    if (dutyPct >= 50) return '약 2시간';
    if (dutyPct >= 20) return '약 4시간';
    if (dutyPct >= 10) return '약 6시간';
    return '약 8시간+';
  }

  Widget _buildBrightnessPreset(
    String label,
    int value,
    int currentValue,
    double fontSize,
    bool isSmallScreen,
  ) {
    final isSelected = currentValue == value;
    return TextButton(
      onPressed: () => _setBrightness(value),
      style: TextButton.styleFrom(
        backgroundColor: isSelected ? Colors.blue.shade100 : null,
        padding: EdgeInsets.symmetric(
          horizontal: isSmallScreen ? 8 : 12,
          vertical: isSmallScreen ? 2 : 4,
        ),
        minimumSize: Size(isSmallScreen ? 48 : 56, isSmallScreen ? 32 : 36),
        tapTargetSize: MaterialTapTargetSize.shrinkWrap,
      ),
      child: Text(
        label,
        style: TextStyle(
          fontSize: fontSize,
          fontWeight: isSelected ? FontWeight.bold : FontWeight.normal,
        ),
      ),
    );
  }

  Future<void> _applyPreset(_ModePreset preset) async {
    final dataSource = ref.read(ilensDataSourceProvider);
    if (!dataSource.isConnected) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('RunVision이 연결되지 않았습니다'), backgroundColor: Colors.orange),
        );
      }
      return;
    }
    try {
      await ref.read(ilensSettingsProvider.notifier).setHibernationTime(preset.hibernation);
      if (preset.screenOff > 0) {
        await ref.read(ilensSettingsProvider.notifier).setScreenOffTime(preset.screenOff);
      }
    } catch (e) {
      await Future.delayed(const Duration(milliseconds: 200));
      if (mounted && ref.read(ilensConnectionStateProvider)) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('설정 전송 실패. 다시 시도해주세요'), backgroundColor: Colors.red),
        );
      }
    }
  }

  Future<void> _sendCustomSettings() async {
    final onTimeText = _onTimeController.text.trim();
    final cycleText = _cycleController.text.trim();
    if (onTimeText.isEmpty && cycleText.isEmpty) return;

    final dataSource = ref.read(ilensDataSourceProvider);
    if (!dataSource.isConnected) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('RunVision이 연결되지 않았습니다'), backgroundColor: Colors.orange),
        );
      }
      return;
    }

    try {
      if (onTimeText.isNotEmpty) {
        final onTime = int.tryParse(onTimeText);
        if (onTime != null && onTime > 0) {
          await ref.read(ilensSettingsProvider.notifier).setHibernationTime(onTime);
        }
      }
      if (cycleText.isNotEmpty) {
        final cycle = int.tryParse(cycleText);
        if (cycle != null && cycle >= 0) {
          await ref.read(ilensSettingsProvider.notifier).setScreenOffTime(cycle);
        }
      }
      _onTimeController.clear();
      _cycleController.clear();
      if (mounted) FocusScope.of(context).unfocus();
    } catch (e) {
      await Future.delayed(const Duration(milliseconds: 200));
      if (mounted && ref.read(ilensConnectionStateProvider)) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('설정 전송 실패. 다시 시도해주세요'), backgroundColor: Colors.red),
        );
      }
    }
  }

  Future<void> _setBrightness(int value) async {
    final dataSource = ref.read(ilensDataSourceProvider);
    if (!dataSource.isConnected) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('RunVision이 연결되지 않았습니다'), backgroundColor: Colors.orange),
        );
      }
      return;
    }
    try {
      await ref.read(ilensSettingsProvider.notifier).setBrightness(value);
    } catch (e) {
      await Future.delayed(const Duration(milliseconds: 200));
      if (mounted && ref.read(ilensConnectionStateProvider)) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('밝기 설정 실패. 다시 시도해주세요'), backgroundColor: Colors.red),
        );
      }
    }
  }
}

