String _estimateBattery(int hibernation, int screenOff) {
  if (hibernation == 65535) return '약 80분';
  final total = hibernation + screenOff;
  if (total == 0) return '—';
  final dutyPct = hibernation * 100 / total;
  if (dutyPct >= 80) return '약 1.5시간';
  if (dutyPct >= 50) return '약 2시간';
  if (dutyPct >= 20) return '약 4시간';
  if (dutyPct >= 10) return '약 6시간';
  return '약 8시간+';
}

