68	    private var _connectionStartTime as Lang.Number = 0;  // 연결 시작 시간 (Service Discovery 대기용)
69	
70	    // Running Power 계산용 변수
71	    private var _previousAltitude as Lang.Float = 0.0;     // 이전 고도 (m)
72	    private var _previousDistance as Lang.Float = 0.0;     // 이전 거리 (m)
73	    private var _userWeight as Lang.Float = 70.0;          // 사용자 체중 (kg, 기본값 70kg)
