87	    private const SLOW_DEVICE_THRESHOLD_MS = 500;          // 500ms 이상이면 느린 기기
88	
89	    // 자동 재연결 관련 변수 (추가)
90	    private var _lastReconnectTime as Lang.Number = 0;       // 마지막 재연결 시도 시간 (초)
91	    private var _needsReconnect as Lang.Boolean = false;     // 재연결 필요 플래그
92	    private const RECONNECT_FAST_INTERVAL = 5;               // 빠른 재연결 간격 (초)
93	    private const RECONNECT_SLOW_INTERVAL = 60;              // 느린 재연결 간격 (초)
94	    private const RECONNECT_FAST_MAX = 5;                    // 빠른 재연결 최대 횟수
95	
96	    // ✅ Pairing 타임아웃 (Connecting 상태 멈춤 방지)
97	    // System.getTimer() 사용 - 액티비티 시작 전에도 동작
98	    private var _pairingStartTime as Lang.Number = 0;        // 페어링 시작 시간 (ms, System.getTimer())
99	    private var _pairingRetryCount as Lang.Number = 0;       // 페어링 재시도 횟수
100	    private const PAIRING_TIMEOUT_MS = 3000;                 // 3초 타임아웃 (ms)
101	    private const PAIRING_MAX_RETRIES = 3;                   // 최대 3회 재시도
