103	    // 스캔 타임아웃: 2-retry + 새 기기 등록 모드
104	    private var _scanStartTime as Lang.Number = 0;           // 스캔 시작 시간 (ms)
105	    private var _savedDeviceScanAttempts as Lang.Number = 0; // 저장된 기기 탐색 시도 횟수
106	    private const SCAN_TIMEOUT_MS_IQ = 3000;                 // 스캔 타임아웃 (ms)
107	
108	    //! FR55 호환성: Profile을 lazy 생성 (파일 로드 시 BLE API 호출 방지)
109	    private function getExerciseProfile() as Lang.Dictionary {
110	        return {
111	            :uuid => BluetoothLowEnergy.stringToUuid("4b329cf2-3816-498c-8453-ee8798502a08"),
112	            :characteristics => [
113	                { :uuid => BluetoothLowEnergy.stringToUuid("c259c1bd-18d3-c348-b88d-5447aea1b615") }
114	            ]
115	        };
116	    }
117	
118	    //! Constructor
119	    function initialize() {
120	        DataField.initialize();
121	
122	        // BLE Delegate 설정 (별도 클래스 필요 - DataField는 BleDelegate 상속 불가)
123	        try {
124	            var delegate = new $.RunVisionBleDelegate(self);
125	            BluetoothLowEnergy.setDelegate(delegate);
126	
127	            // 초기화 시 기존 bonding 정보 삭제 (iLens는 multi-bonding 미지원)
128	            // FR55 호환성: has 연산자로 API 존재 여부 확인
129	            if (BluetoothLowEnergy has :getPairedDevices) {
130	                try {
131	                    var paired = BluetoothLowEnergy.getPairedDevices();
132	                    var dev = paired.next() as BluetoothLowEnergy.Device;
133	                    while (dev != null) {
134	                        BluetoothLowEnergy.unpairDevice(dev);
135	                        dev = paired.next() as BluetoothLowEnergy.Device;
136	                    }
137	                } catch (ex2) {
138	                    // 무시
139	                }
140	            }
141	
142	            _scanStatus = "INIT_OK";
143	            addBleLog("READY");
144	        } catch (ex) {
145	            _scanStatus = "INIT_ERR";
146	            addBleLog("ERR:init");
147	        }
148	    }
149	
150	    //! Check for already paired devices (Passive Connection)
151	    //! iLens는 multi-bonding 미지원 → 항상 새로 스캔/페어링
152	    private function checkPairedDevices() as Void {
153	        try {
154	            // 기존 페어링 정보 삭제 (iLens가 다른 기기와 페어링되었을 수 있음)
155	            // FR55 호환성: has 연산자로 API 존재 여부 확인
156	            if (BluetoothLowEnergy has :getPairedDevices) {
157	                var pairedDevices = BluetoothLowEnergy.getPairedDevices();
158	                var device = pairedDevices.next() as BluetoothLowEnergy.Device;
159	                while (device != null) {
160	                    try {
161	                        BluetoothLowEnergy.unpairDevice(device);
162	                        addBleLog("UNPAIR");
163	                    } catch (ex) {
164	                        // 무시
165	                    }
166	                    device = pairedDevices.next() as BluetoothLowEnergy.Device;
167	                }
168	            }
169	
170	            // 항상 새로 스캔 (iLens는 multi-bonding 미지원)
171	            try {
172	                BluetoothLowEnergy.registerProfile(getExerciseProfile());
173	                BluetoothLowEnergy.setScanState(BluetoothLowEnergy.SCAN_STATE_SCANNING);
174	                _scanStatus = "SCANNING";
175	                addBleLog("SCAN");
176	            } catch (ex) {
177	                _scanStatus = "SCAN_ERR";
178	                addBleLog("ERR:scan");
179	            }
180	        } catch (ex) {
181	            _scanStatus = "ERR:init";
182	            addBleLog("ERR:init");
183	        }
184	    }
185	
186	    //! Add BLE debug log (최대 8줄, 순환) - DEBUG MODE
187	    public function addBleLog(msg as Lang.String) as Void {
188	        _bleDebugLogs[_bleLogIndex] = msg;
189	        _bleLogIndex = (_bleLogIndex + 1) % 8;
190	        try {
191	            WatchUi.requestUpdate();
192	        } catch (e) {
193	            // UI가 아직 준비되지 않았을 수 있음
194	        }
195	    }
196	
197	    //! Add TX debug log (최대 8줄, 순환) - DEBUG MODE
198	    private function addTxLog(msg as Lang.String) as Void {
199	        _txDebugLogs[_txLogIndex] = msg;
200	        _txLogIndex = (_txLogIndex + 1) % 8;
201	        try {
202	            WatchUi.requestUpdate();
203	        } catch (e) {
204	            // UI가 아직 준비되지 않았을 수 있음
205	        }
206	    }
207	
208	    //! Called when activity is started
209	    function onTimerStart() as Void {
210	        // DFLogger.reset();
211	        // DFLogger.log("=== Activity Started ===");
212	
213	        addBleLog("START");
214	
215	        // Passive Connection: 페어링된 기기 확인
216	        if (!_isConnected) {
217	            checkPairedDevices();
218	        }
219	
220	        WatchUi.requestUpdate();
221	    }
222	
223	    //! Called when activity is stopped
224	    function onTimerStop() as Void {
225	        // Stop scanning (BLE Scanner 방식)
226	        BluetoothLowEnergy.setScanState(BluetoothLowEnergy.SCAN_STATE_OFF);
227	        addBleLog("STOP");
228	    }
229	
230	    //! Called when activity is paused
231	    function onTimerPause() as Void {
232	        // Timer paused
233	    }
234	
235	    //! Called when activity is resumed
236	    function onTimerResume() as Void {
237	        // Timer resumed
238	    }
239	
240	    //! Called when lap button is pressed
241	    function onTimerLap() as Void {
242	        // Lap recorded
243	    }
244	
245	    //! Called when activity is reset
246	    function onTimerReset() as Void {
247	        // Reset statistics
248	        _totalSpeed = 0.0;
249	        _speedSamples = 0;
250	        _maxHeartRate = 0;
251	        _avgSpeedLabel = "---";
252	        _maxHrLabel = "---";
253	        _paceLabel = "--:--";
254	        _distanceLabel = "0.00";
255	        _timeLabel = "0:00";
256	        _speedLabel = "---";
257	        _hrLabel = "---";
258	        _cadenceLabel = "---";
259	        _devicesFound = 0;
260	        _elapsedSeconds = 0;  // ✅ 경과 시간 초기화
261	    }
262	
263	    //! Called each second to compute and display values (DataField)
264	    //! @param info Activity.Info object
265	    function compute(info as Activity.Info) as Void {
266	        // Passive Connection 타임아웃 (3초)
267	        if (_scanStatus.equals("PASSIVE") && !_isConnected && _elapsedSeconds >= 3) {
268	            try {
269	                // FR55 호환성: has 연산자로 API 존재 여부 확인
270	                if (_connectedDevice != null && (BluetoothLowEnergy has :unpairDevice)) {
271	                    BluetoothLowEnergy.unpairDevice(_connectedDevice);
272	                }
273	                _connectedDevice = null;
274	                _profileRegistered = false;
275	                BluetoothLowEnergy.registerProfile(getExerciseProfile());
276	                _scanStatus = "RESCAN";
277	                addBleLog("RESCAN");
278	            } catch (ex) {
279	                addBleLog("ERR:rescan");
280	            }
281	        }
282	
283	        // ✅ Pairing 타임아웃 (Connecting 상태 멈춤 방지)
284	        // System.getTimer() 사용 - 액티비티 시작 전에도 동작
285	        if (_pairingStartTime > 0 && !_isConnected) {
286	            var pairingDuration = System.getTimer() - _pairingStartTime;
287	            if (pairingDuration >= PAIRING_TIMEOUT_MS) {
288	                _pairingRetryCount++;
289	                addBleLog("PAIR_TO:" + _pairingRetryCount);  // Pairing Timeout + retry count
290	                _pairingStartTime = 0;
291	
292	                try {
293	                    if (_connectedDevice != null && (BluetoothLowEnergy has :unpairDevice)) {
294	                        BluetoothLowEnergy.unpairDevice(_connectedDevice);
295	                    }
296	                    _connectedDevice = null;
297	                    _isReconnecting = false;
298	                } catch (ex) {
299	                    // 무시
300	                }
301	
302	                if (_pairingRetryCount >= PAIRING_MAX_RETRIES) {
303	                    // 3회 실패 → CONN_ERR
304	                    _scanStatus = "CONN_ERR";
305	                    _pairingRetryCount = 0;
306	                    addBleLog("CONN_ERR");
307	                } else {
308	                    // 재시도: 즉시 다시 pairing
309	                    _scanStatus = "RETRY " + _pairingRetryCount;
310	                    if (_lastScanResult != null) {
311	                        try {
312	                            _pairingStartTime = System.getTimer();
313	                            _connectedDevice = BluetoothLowEnergy.pairDevice(_lastScanResult);
314	                            if (_connectedDevice == null) {
315	                                _pairingStartTime = 0;
316	                            }
317	                        } catch (ex) {
318	                            _pairingStartTime = 0;
319	                        }
320	                    }
321	                }
322	            }
323	        }
324	
325	        // 스캔 타임아웃: 2-retry + 새 기기 등록 모드
326	        // 저장된 기기 3s×2 미발견 → savedRLensName 삭제 후 any rLens 스캔 3s×2
327	        if ((_scanStatus.equals("SCANNING") || _scanStatus.equals("NEW_DEV")) && _scanStartTime > 0 && !_isConnected) {
328	            var scanElapsed = System.getTimer() - _scanStartTime;
329	            if (scanElapsed >= SCAN_TIMEOUT_MS_IQ) {
330	                _scanStartTime = 0;
331	                _savedDeviceScanAttempts++;
332	
333	                var savedDevice = Application.Storage.getValue("savedRLensName");
334	
335	                if (savedDevice != null && _savedDeviceScanAttempts >= 2) {
336	                    // 저장된 기기 2회 실패 → 새 기기 등록 모드
337	                    Application.Storage.deleteValue("savedRLensName");
338	                    _savedDeviceScanAttempts = 0;
339	                    _scanStartTime = System.getTimer();  // 새 타임아웃 윈도우
340	                    addBleLog("NEW_DEV");
341	                    _scanStatus = "NEW_DEV";
342	                } else if (savedDevice == null && _savedDeviceScanAttempts >= 2) {
343	                    // 새 기기 등록 모드 또는 최초 실행 2회 실패 → 에러
344	                    _scanStatus = "SCAN_FAIL";
345	                    _savedDeviceScanAttempts = 0;
346	                    addBleLog("SCAN_FAIL");
347	                } else {
348	                    // 1차 실패 → 재시도 (스캔 계속 유지)
349	                    _scanStartTime = System.getTimer();
350	                    addBleLog("SCAN_TO:" + _savedDeviceScanAttempts);
351	                }
352	
353	                WatchUi.requestUpdate();
354	            }
355	        }
356	
357	        // Auto-reconnect (연결 끊김 시)
358	        // 전략: 1-5회는 5초 간격 단순 재연결, 6회째 unpair 후 재스캔, 이후 1분마다 재스캔
359	        if (_needsReconnect && !_isConnected && !_isReconnecting) {
360	            var timeSinceLastTry = _elapsedSeconds - _lastReconnectTime;
361	            var shouldTry = false;
362	            var interval = 0;
363	
364	            if (_reconnectAttempts < RECONNECT_FAST_MAX) {
365	                // 1-5회: 5초 간격
366	                interval = RECONNECT_FAST_INTERVAL;
367	                shouldTry = (timeSinceLastTry >= interval);
368	            } else {
369	                // 6회 이후: 1분 간격
370	                interval = RECONNECT_SLOW_INTERVAL;
371	                shouldTry = (timeSinceLastTry >= interval);
372	            }
373	
374	            if (shouldTry) {
375	                _reconnectAttempts++;
376	                _lastReconnectTime = _elapsedSeconds;
377	                _isReconnecting = true;
378	
379	                if (_reconnectAttempts <= RECONNECT_FAST_MAX && _lastScanResult != null) {
380	                    // 1-5회: 단순 재연결 시도 (빠름)
381	                    addBleLog("RE:" + _reconnectAttempts);
382	                    _scanStatus = "RECONN " + _reconnectAttempts;
383	                    try {
384	                        _pairingStartTime = System.getTimer();  // ✅ 타임아웃 추적 시작
385	                        _connectedDevice = BluetoothLowEnergy.pairDevice(_lastScanResult);
386	                        if (_connectedDevice == null) {
387	                            _isReconnecting = false;
388	                            _pairingStartTime = 0;  // 실패 시 리셋
389	                        }
390	                    } catch (ex) {
391	                        _isReconnecting = false;
392	                        _pairingStartTime = 0;  // 실패 시 리셋
393	                    }
394	                } else {
395	                    // 6회 이후: unpair 후 새로 스캔
396	                    addBleLog("RESCAN:" + _reconnectAttempts);
397	                    _scanStatus = "RESCAN";
398	                    try {
399	                        // 기존 bonding 삭제 (FR55 호환성: has 연산자로 확인)
400	                        if (BluetoothLowEnergy has :getPairedDevices) {
401	                            var paired = BluetoothLowEnergy.getPairedDevices();
402	                            var dev = paired.next() as BluetoothLowEnergy.Device;
403	                            while (dev != null) {
404	                                BluetoothLowEnergy.unpairDevice(dev);
405	                                dev = paired.next() as BluetoothLowEnergy.Device;
406	                            }
407	                        }
408	                        // 새로 스캔 시작
409	                        BluetoothLowEnergy.setScanState(BluetoothLowEnergy.SCAN_STATE_SCANNING);
410	                        _isReconnecting = false;
411	                    } catch (ex) {
412	                        _isReconnecting = false;
413	                    }
414	                }
415	            }
416	        }
417	
418	        // ✅ Lazy Loading: Characteristic 필요할 때 획득 (매초 1회 시도)
419	        if (_isConnected && _connectedDevice != null && _exerciseCharacteristic == null) {
420	            try {
421	                _exerciseCharacteristic = tryGetServiceCharacteristic(
422	                    ILensProtocol.EXERCISE_SERVICE_UUID,
423	                    ILensProtocol.EXERCISE_DATA_UUID,
424	                    3  // 3번 동기 재시도
425	                );
426	                _charRetryCount = 0;  // 성공 시 리셋
427	                addBleLog("CHAR OK");
428	                _scanStatus = "READY";
429	            } catch (ex) {
430	                _charRetryCount++;
431	                if (_charRetryCount >= 5) {
432	                    // 5회 실패 → 재연결 트리거
433	                    _charRetryCount = 0;
434	                    _isConnected = false;
435	                    _connectedDevice = null;
436	                    _scanStatus = "RECONN...";
437	                    addBleLog("RECONN");
438	                    // → auto-reconnect 로직이 다음 compute에서 동작
439	                } else {
440	                    // 실패 횟수 표시 (1~4) - 사용자가 이상 상태 인지 가능
441	                    _scanStatus = "CHAR_FAIL(" + _charRetryCount + ")";
442	                }
443	            }
444	        }
445	
446	        // ========== 데이터 수집 (라벨 업데이트) ==========
447	        // ActiveLook 패턴: has 체크 + false 체크
448	
449	        // Get current speed (m/s -> km/h)
450	        var speedMs = info != null && info has :currentSpeed ? info.currentSpeed : null;
451	        var speedKmh = 0;
452	        var paceSeconds = 0;  // ← Pace를 초 단위로 저장 (iLens 전송용)
453	        var speedValid = speedMs != null && speedMs > 0;
454	
455	        if (speedValid) {
456	            speedKmh = ((speedMs * 3.6) + 0.5).toNumber();  // ✅ 반올림
457	            _speedLabel = speedKmh.format("%d");
458	
459	            // Calculate pace (min/km) - 러너들은 Pace에 익숙
460	            var paceMinPerKm = 60.0 / (speedMs * 3.6);
461	            var paceMin = paceMinPerKm.toNumber();
462	            var paceSec = ((paceMinPerKm - paceMin) * 60).toNumber();
463	            _paceLabel = paceMin.format("%d") + ":" + paceSec.format("%02d");
464	
465	            // iLens 전송용: Pace를 총 초로 변환 (예: 4:25 → 265초)
466	            // iLens 펌웨어가 60으로 나눠서 표시: 265 / 60 = 4.42
467	            paceSeconds = paceMin * 60 + paceSec;
468	
469	            // Update average speed
470	            _totalSpeed += speedMs * 3.6;
471	            _speedSamples++;
472	            var avgSpeed = (_totalSpeed / _speedSamples).toNumber();
473	            _avgSpeedLabel = avgSpeed.format("%d");
474	        } else {
475	            _speedLabel = "0";
476	            _paceLabel = "--:--";
477	        }
478	
479	        // Get current heart rate (ActiveLook 패턴)
480	        var hr = info != null && info has :currentHeartRate ? info.currentHeartRate : null;
481	        var hrValid = hr != null && hr > 0;
482	        if (hrValid) {
483	            _hrLabel = hr.format("%d");
484	
485	            // Track max heart rate
486	            if (hr > _maxHeartRate) {
487	                _maxHeartRate = hr;
488	                _maxHrLabel = hr.format("%d");
489	            }
490	        } else {
491	            _hrLabel = "---";
492	            hr = 0;
493	        }
494	
495	        // Get current cadence (ActiveLook 패턴)
496	        var cadence = info != null && info has :currentCadence ? info.currentCadence : null;
497	        var cadenceValid = cadence != null && cadence > 0;
498	        if (cadenceValid) {
499	            _cadenceLabel = cadence.format("%d");
500	        } else {
501	            _cadenceLabel = "---";
502	            cadence = 0;
503	        }
504	
505	        // Get elapsed distance (meters) - Running Power 계산에 필요
506	        var distance = info != null && info has :elapsedDistance ? info.elapsedDistance : null;
507	        var distanceValid = distance != null && distance > 0;
508	        if (distanceValid) {
509	            var distanceKm = distance / 1000.0;
510	            _distanceLabel = distanceKm.format("%.2f");
511	        } else {
512	            _distanceLabel = "0.00";
513	            distance = 0;
514	        }
515	
516	        // ========== Running Power 계산 ==========
517	        // Power Meter 대신 GPS 데이터로 Running Power 추정
518	        // Formula: Power = Weight × Speed × (1 + |Grade|/100) × k
519	        //   - Weight: 체중 (kg)
520	        //   - Speed: 속도 (m/s)
521	        //   - Grade: 경사도 (%)
522	        //   - k: 보정 상수 (≈1.8, Garmin/Stryd 기준)
523	
524	        var power = 0;
525	
526	        // 1. UserProfile에서 체중 가져오기 (처음 한 번만)
527	        if (!_weightInitialized) {
528	            try {
529	                var profile = UserProfile.getProfile();
530	                if (profile != null && profile has :weight) {
531	                    var profileWeight = profile.weight;  // grams
532	                    if (profileWeight != null && profileWeight > 0) {
533	                        _userWeight = profileWeight / 1000.0;  // g → kg
534	                        // DFLogger.log("[POWER] User weight: " + _userWeight.format("%.1f") + " kg");
535	                    }
536	                }
537	            } catch (ex) {
538	                // DFLogger.logError("POWER", "Failed to get user weight");
539	            }
540	            _weightInitialized = true;
541	        }
542	
543	        // 2. 고도 가져오기
544	        var altitude = info != null && info has :altitude ? info.altitude : null;
545	
546	        // 3. Running Power 계산 (속도와 거리가 유효할 때만)
547	        if (speedValid && distanceValid && altitude != null) {
548	            // 경사도 계산 (최근 구간의 고도 변화)
549	            var grade = 0.0;
550	            var distanceDelta = distance - _previousDistance;
551	
552	            if (distanceDelta > 10.0) {  // 10m 이상 이동했을 때만 경사도 계산
553	                var altitudeDelta = altitude - _previousAltitude;
554	                grade = (altitudeDelta / distanceDelta) * 100.0;  // % 단위
555	
556	                // 경사도 범위 제한 (-30% ~ +30%)
557	                if (grade < -30.0) { grade = -30.0; }
558	                if (grade > 30.0) { grade = 30.0; }
559	
560	                // 다음 계산을 위해 저장
561	                _previousAltitude = altitude;
562	                _previousDistance = distance;
563	            }
564	
565	            // Running Power 계산
566	            // Power = Weight × Speed × (1 + |Grade|/100) × 1.8
567	            var gradeFactor = 1.0 + (grade > 0 ? grade : -grade) / 100.0;  // |Grade|/100
568	            power = (_userWeight * speedMs * gradeFactor * 1.8).toNumber();
569	
570	            // 파워 범위 제한 (0-999 watts, 일반 러너 범위)
571	            if (power < 0) { power = 0; }
572	            if (power > 999) { power = 999; }
573	        }
574	
575	        // ✅ Activity.Info에서 실제 경과 시간 사용 (timerTime = milliseconds)
576	        // compute()는 1초마다 호출되지 않을 수 있으므로 timerTime 사용이 정확함
577	        if (info != null && info has :timerTime && info.timerTime != null) {
578	            _elapsedSeconds = (info.timerTime / 1000).toNumber();  // ms → seconds
579	        } else {
580	            // Fallback: 수동 카운터 (timerTime 미지원 기기)
581	            _elapsedSeconds += 1;
582	        }
583	        var minutes = _elapsedSeconds / 60;
584	        var secs = _elapsedSeconds % 60;
585	        _timeLabel = minutes.format("%d") + ":" + secs.format("%02d");
586	
587	        // ========== iLens 전송: Queue 방식 (Flutter와 동일) ==========
588	        // 5초마다 모든 메트릭을 queue에 추가 → 순차 전송
589	        // iLens는 WRITE_WITH_RESPONSE만 지원 → onCharacteristicWrite() callback에서 다음 패킷 전송
590	        _computeCount++;
591	        if (_isConnected && _exerciseCharacteristic != null && _computeCount % 5 == 0) {
592	            try {
593	                // 1. Write 진행 중이 아닐 때만 queue 초기화
594	                if (!_isWriting) {
595	                    _writeQueue = [] as Lang.Array<Lang.ByteArray>;
596	
597	                    // Queue에 5개 메트릭 추가 (v1.0.2: Sport Time 사용, Power/Current Time 제거)
598	                    _writeQueue.add(ILensProtocol.createExerciseTimePacket(_elapsedSeconds));  // ⭐ Sport Time (0x03)
599	                    _writeQueue.add(ILensProtocol.createVelocityPacket(paceSeconds));          // Pace
600	                    _writeQueue.add(ILensProtocol.createHeartRatePacket(hr));                  // Heart Rate
601	                    _writeQueue.add(ILensProtocol.createCadencePacket(cadence));              // Cadence
602	                    _writeQueue.add(ILensProtocol.createDistancePacket(distance != null ? distance : 0));  // Distance
603	
604	                    // DFLogger.log("[TX] pace=" + paceSeconds + " hr=" + hr + " cad=" + cadence + " pwr=" + power);
605	
606	                    // 화면에 핵심 메트릭만 표시
607	                    addTxLog("P:" + _paceLabel + " T:" + _timeLabel);
608	
609	                    processWriteQueue();
610	                }
611	            } catch (ex) {
612	                addTxLog("q:err");
613	                // DFLogger.logError("QUEUE", "Queue error");
614	            }
615	        }
616	    }
