660	    //! Called when characteristic write completes (WRITE_WITH_RESPONSE)
661	    function onCharacteristicWrite(characteristic as BluetoothLowEnergy.Characteristic, status as BluetoothLowEnergy.Status) as Void {
662	        _isWriting = false;
663	
664	        if (status != BluetoothLowEnergy.STATUS_SUCCESS) {
665	            addTxLog("ERR:wr");
666	            _scanStatus = "WRITE_ERR";
667	            _writeQueue = [] as Lang.Array<Lang.ByteArray>;
668	            return;
669	        }
670	
671	        // 속도 감지 (첫 Write 콜백 시)
672	        if (!_speedDetected && _writeStartTime > 0) {
673	            var elapsed = System.getTimer() - _writeStartTime;
674	            _speedDetected = true;
675	            _writeStartTime = 0;
676	
677	            if (elapsed > SLOW_DEVICE_THRESHOLD_MS) {
678	                // 느린 기기 → DEFAULT 모드로 전환
679	                _useDefaultWrite = true;
680	                addBleLog("MODE:DEFAULT");
681	            } else {
682	                // 빠른 기기 → WITH_RESPONSE 유지
683	                addBleLog("MODE:RESPONSE");
684	            }
685	        }
686	
687	        // 다음 패킷 전송
688	        processWriteQueue();
689	    }
