691	    //! Process write queue (순차 전송)
692	    private function processWriteQueue() as Void {
693	        if (_isWriting) { return; }
694	        if (_writeQueue.size() == 0) { return; }
695	
696	        var packet = _writeQueue[0];
697	        _writeQueue = _writeQueue.slice(1, null) as Lang.Array<Lang.ByteArray>;
698	
699	        _isWriting = true;
700	        sendToILens(packet);
701	    }
