714	            _needsReconnect = false;
715	            _isReconnecting = false;
716	            _scanStartTime = 0;           // 스캔 타임아웃 추적 종료
717	            _savedDeviceScanAttempts = 0; // 스캔 시도 횟수 리셋
718	            _scanStatus = "CONNECTED";
719	            addBleLog("CONN OK");
720	            // DFLogger.logBle("CONNECTED", "Device connected");
721	        } else {
722	            _isConnected = false;
723	            _connectedDevice = null;
724	            _exerciseCharacteristic = null;
725	            _charRetryCount = 0;  // 재시도 카운터 리셋
726	            _connectionStartTime = 0;
727	            _pairingStartTime = 0;  // ✅ 타임아웃 추적 종료
728	            // 속도 감지 리셋 (재연결 시 다시 측정)
729	            _useDefaultWrite = false;
730	            _writeStartTime = 0;
731	            _speedDetected = false;
732	            _scanStatus = "DISCONN";
733	            addBleLog("DISCONN");
