747	    //! Try and retry to get a characteristic from a service (ActiveLook 패턴 완전 복제)
748	    //! @param serviceUuid Service UUID
749	    //! @param characteristicUuid Characteristic UUID
750	    //! @param nbRetry Number of retries (권장: 5)
751	    //! @return Characteristic
752	    //! @throws InvalidValueException if not found after retries
753	    private function tryGetServiceCharacteristic(
754	        serviceUuid as BluetoothLowEnergy.Uuid,
755	        characteristicUuid as BluetoothLowEnergy.Uuid,
756	        nbRetry as Lang.Number
757	    ) as BluetoothLowEnergy.Characteristic {
758	        if (_connectedDevice == null) {
759	            throw new Lang.InvalidValueException("(E) Not connected");
760	        }
761	
762	        var dev = _connectedDevice as BluetoothLowEnergy.Device;
763	        var service = dev.getService(serviceUuid);
764	
765	        // ✅ RETRY PATTERN: nbRetry번 재시도 (ActiveLook 방식)
766	        for (var i = 0; i < nbRetry; i++) {
767	            if (service == null) {
768	                service = dev.getService(serviceUuid);  // ← Service 재시도
769	                if (service == null) {
770	                    System.println("[RETRY " + i + "] Service still null");
771	                } else {
772	                    System.println("[RETRY " + i + "] Service found!");
773	                }
774	            } else {
775	                var characteristic = service.getCharacteristic(characteristicUuid);
776	                if (characteristic != null) {
777	                    // ✅ 성공 시 즉시 리턴
778	                    System.println("tryGetServiceCharacteristic: success at retry " + i);
779	                    return characteristic;
780	                } else {
781	                    System.println("[RETRY " + i + "] Service OK but Char null");
782	                }
783	            }
784	        }
785	
786	        // ✅ nbRetry번 실패 시 예외 발생
787	        if (service == null) {
788	            System.println("FINAL: Service is NULL");
789	            throw new Lang.InvalidValueException(
790	                "(E) Could not get service after " + nbRetry + " retries"
791	            );
792	        }
793	        System.println("FINAL: Service OK but Characteristic is NULL");
794	        throw new Lang.InvalidValueException(
795	            "(E) Could not get characteristic after " + nbRetry + " retries"
796	        );
797	    }
