799	    //! Send data to iLens (WRITE_WITH_RESPONSE only)
800	    //! Send data to iLens with auto-detected Write Type
801	    //! - 빠른 기기: WRITE_WITH_RESPONSE (안정적, ~80ms)
802	    //! - 느린 기기: WRITE_TYPE_DEFAULT (빠름, FR55용)
803	    private function sendToILens(packet as Lang.ByteArray) as Void {
804	        if (_exerciseCharacteristic == null) {
805	            _isWriting = false;
806	            return;
807	        }
808	
809	        try {
810	            // 속도 측정 시작 (첫 Write 시)
811	            if (!_speedDetected && _writeStartTime == 0) {
812	                _writeStartTime = System.getTimer();
813	            }
814	
815	            // Write Type 선택
816	            var writeType = BluetoothLowEnergy.WRITE_TYPE_WITH_RESPONSE;
817	            if (_useDefaultWrite) {
818	                writeType = BluetoothLowEnergy.WRITE_TYPE_DEFAULT;
819	            }
820	
821	            _exerciseCharacteristic.requestWrite(packet, {:writeType => writeType});
822	        } catch (ex) {
823	            addTxLog("ERR:tx");
824	            _isWriting = false;
825	        }
826	    }
