838	    //! Called when profile registration completes
839	    function onProfileRegister(uuid as BluetoothLowEnergy.Uuid, status as BluetoothLowEnergy.Status) as Void {
840	        if (status == BluetoothLowEnergy.STATUS_SUCCESS) {
841	            _profileRegistered = true;
842	            _scanStatus = "PROF_OK";
843	
844	            try {
845	                BluetoothLowEnergy.setScanState(BluetoothLowEnergy.SCAN_STATE_SCANNING);
846	                addBleLog("SCANNING");
847	            } catch (ex) {
848	                _scanStatus = "SCAN_ERR";
849	            }
850	        } else {
851	            _scanStatus = "PROF_FAIL";
852	        }
853	
854	        WatchUi.requestUpdate();
855	    }
856	
857	    //! Called when rLens device is found during scanning
858	    function onScanResult(scanResult as BluetoothLowEnergy.ScanResult) as Void {
859	        addBleLog("FOUND");
860	        System.println("iLens found, RSSI=" + scanResult.getRssi());
861	
862	        // Save device name on first connection (device name = serial number)
863	        if (Application.Storage.getValue("savedRLensName") == null) {
864	            var raw = scanResult.getRawData();
865	            if (raw != null) {
866	                var rawStr = "";
867	                for (var i = 0; i < raw.size(); i++) {
868	                    var c = raw[i];
869	                    if (c >= 0x20 && c <= 0x7E) { rawStr += c.toChar(); }
870	                }
871	                // Extract device name: find "rlens" and read until whitespace
872	                var lowerStr = rawStr.toLower();
873	                var idx = lowerStr.find("rlens");
874	                if (idx != -1) {
875	                    var nameEnd = idx;
876	                    while (nameEnd < rawStr.length()) {
877	                        var ch = rawStr.substring(nameEnd, nameEnd + 1);
878	                        if (ch.equals(" ")) { break; }
879	                        nameEnd++;
880	                    }
881	                    var deviceName = rawStr.substring(idx, nameEnd);
882	                    Application.Storage.setValue("savedRLensName", deviceName);
883	                    System.println("Saved rLens device: " + deviceName);
884	                }
885	            }
886	        }
887	
888	        // Auto-connect
889	        if (!_isConnected && _connectedDevice == null) {
890	            _devicesFound++;
891	            _lastScanResult = scanResult;
892	
893	            BluetoothLowEnergy.setScanState(BluetoothLowEnergy.SCAN_STATE_OFF);
894	
895	            addBleLog("PAIRING");
896	            _pairingStartTime = System.getTimer();  // ✅ 타임아웃 추적 시작
897	            _connectedDevice = BluetoothLowEnergy.pairDevice(scanResult);
898	
899	            if (_connectedDevice == null) {
900	                _scanStatus = "PAIR_FAIL";
901	                _pairingStartTime = 0;  // 실패 시 리셋
902	            } else {
903	                _scanStatus = "PAIRING";
904	            }
905	        }
906	
907	        WatchUi.requestUpdate();
908	    }
