910	    //! Called when scan state changes
911	    function onScanStateChange(scanState as BluetoothLowEnergy.ScanState, status as BluetoothLowEnergy.Status) as Void {
912	        if (scanState == BluetoothLowEnergy.SCAN_STATE_SCANNING) {
913	            if (status == BluetoothLowEnergy.STATUS_SUCCESS) {
914	                _scanStatus = "SCANNING";
915	                _scanStartTime = System.getTimer();  // 타임아웃 추적 시작
916	            } else {
917	                _scanStatus = "SCAN_ERR";
918	                _scanStartTime = 0;
919	            }
920	        } else if (scanState == BluetoothLowEnergy.SCAN_STATE_OFF) {
921	            // 스캔 중지 = 기기 찾음, 연결 시도 중
922	            _scanStatus = "Connecting...";
923	            _scanStartTime = 0;  // 스캔 종료 — 타임아웃 추적 불필요
924	        }
925	
926	        WatchUi.requestUpdate();
927	    }
928	
929	    //! Called when there's a passive connection (already paired)
930	    function onPassiveConnection(device as BluetoothLowEnergy.Device) as Void {
931	        _isConnected = true;
932	        _scanStatus = "PASSIVE";
933	        WatchUi.requestUpdate();
934	    }
935	
