943	//! BLE Delegate - 별도 클래스 (DataField는 다중 상속 불가)
944	class RunVisionBleDelegate extends BluetoothLowEnergy.BleDelegate {
945	    private var _view;
946	
947	    function initialize(view) {
948	        BleDelegate.initialize();
949	        _view = view;
950	        // System.println("RunVisionBleDelegate initialized");
951	    }
