953	    //! rLens 기기 식별: 이름 전체 매칭 (기기명=시리얼번호, e.g. "rlens-e70b4")
954	    //! 저장된 기기명이 있으면 해당 기기만 연결 (다른 사람 기기 연결 방지)
955	    function onScanResults(results as BluetoothLowEnergy.Iterator) as Void {
956	        var savedDevice = Application.Storage.getValue("savedRLensName");
957	        var r = results.next() as BluetoothLowEnergy.ScanResult;
958	        while (r != null) {
959	            var raw = r.getRawData();
960	
961	            if (raw != null) {
962	                // Raw data 전체를 소문자 문자열로 변환
963	                var rawStr = "";
964	                for (var i = 0; i < raw.size(); i++) {
965	                    var c = raw[i];
966	                    if (c >= 0x20 && c <= 0x7E) {
967	                        rawStr += c.toChar();
968	                    }
969	                }
970	
971	                var lowerStr = rawStr.toLower();
972	                if (lowerStr.find("rlens") != -1) {
973	                    if (savedDevice != null) {
974	                        // 저장된 기기명과 정확히 일치하는 경우만 연결
975	                        if (rawStr.find(savedDevice) != -1) {
976	                            _view.onScanResult(r);
977	                            return;
978	                        }
979	                        // 불일치: 다른 사람의 rLens, 스킵
980	                    } else {
981	                        // 최초 실행: 처음 발견된 rLens에 연결
982	                        _view.onScanResult(r);
983	                        return;
984	                    }
985	                }
986	            }
987	
988	            r = results.next() as BluetoothLowEnergy.ScanResult;
989	        }
990	    }
